import { useState, useRef, useEffect } from 'react';
import useCreateProducto from '@hooks/productos/useCreateProducto';
import { FaTimes, FaUpload, FaImage, FaSpinner } from 'react-icons/fa';
import DropdownCategorias from './DropdownCategorias';
import '@styles/crearProducto.css';

const CrearProductoPopup = ({ show, setShow, onProductoCreated }) => {
    const { handleCreate, loading, errors, clearErrors, setErrors } = useCreateProducto((nuevoProducto) => {
        setShow(false);
        resetForm();
        if (onProductoCreated) onProductoCreated(nuevoProducto);
    });

    useEffect(() => {
        if (show) {
            document.body.classList.add('no-scroll');
        } else {
            document.body.classList.remove('no-scroll');
        }

        return () => {
            document.body.classList.remove('no-scroll');
        };
    }, [show]);

    const [formData, setFormData] = useState({
        nombre: '',
        descripcion: '',
        precio: '',
        categoria: '',
        subcategoria: '',
        stock: '',
        marca: '',
        codigoSKU: '',
        activo: true,
        oferta: false,
        descuento: ''
    });

    const [imagen, setImagen] = useState(null);
    const [previewImagen, setPreviewImagen] = useState(null);
    const [alert, setAlert] = useState(null);
    const [dropdownActivo, setDropdownActivo] = useState(null);
    const fileInputRef = useRef(null);

    const showAlert = (message) => {
        setAlert(message);
        setTimeout(() => setAlert(null), 2000);
    };

    const isFormValid = () => {
        return (
            formData.nombre.trim().length >= 3 &&
            formData.descripcion.trim().length >= 10 &&
            formData.precio.length > 0 &&
            formData.categoria !== '' &&
            formData.subcategoria !== '' &&
            formData.stock !== '' &&
            formData.marca.trim().length >= 2 &&
            formData.codigoSKU.trim().length >= 3 &&
            imagen !== null
        );
    };

    const formatPrice = (value) => {
        if (!value) return '';
        const number = value.toString().replace(/\D/g, '');
        return number.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    };

    const handlePriceChange = (e) => {
        const inputValue = e.target.value;
        
        // Permitir solo números y puntos
        if (/[^0-9.]/.test(inputValue) && inputValue !== '') {
            showAlert('El precio solo puede contener números y puntos como separadores');
            return;
        }
        
        // No permitir múltiples puntos consecutivos
        if (/\.{2,}/.test(inputValue)) {
            showAlert('El precio no puede tener múltiples puntos consecutivos');
            return;
        }
        
        // No permitir que comience con punto
        if (/^\./.test(inputValue)) {
            showAlert('El precio no puede comenzar con un punto');
            return;
        }
        
        // Si está vacío, permitir
        if (inputValue === '') {
            setFormData(prev => ({
                ...prev,
                precio: ''
            }));
            return;
        }
        
        // Extraer solo números para validaciones
        const rawValue = inputValue.replace(/\D/g, '');
        
        // Validar longitud máxima
        if (rawValue.length > 8) {
            showAlert('El precio no puede exceder $10.000.000');
            return;
        }
        
        // Validar que sea mayor a 0
        const actualPrice = parseInt(rawValue);
        if (rawValue && actualPrice <= 0) {
            showAlert('El precio debe ser mayor a 0');
            return;
        }
        
        // Validar límite máximo
        if (rawValue && actualPrice > 10000000) {
            showAlert('El precio no puede exceder $10.000.000');
            return;
        }
        
        // Formatear automáticamente solo si hay números
        if (rawValue) {
            const formattedValue = formatPrice(rawValue);
            setFormData(prev => ({
                ...prev,
                precio: formattedValue
            }));
        } else {
            setFormData(prev => ({
                ...prev,
                precio: inputValue
            }));
        }

        if (errors.precio) {
            setErrors(prev => ({
                ...prev,
                precio: null
            }));
        }
    };

    const resetForm = () => {
        setFormData({
            nombre: '',
            descripcion: '',
            precio: '',
            categoria: '',
            subcategoria: '',
            stock: '',
            marca: '',
            codigoSKU: '',
            activo: true,
            oferta: false,
            descuento: ''
        });
        setImagen(null);
        setPreviewImagen(null);
        clearErrors();
    };

    const handleInputChange = (e) => {
        const { name, value, type, checked } = e.target;
        let newValue = type === 'checkbox' ? checked : value;
        
        if (name === 'nombre') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, nombre: '' }));
                return;
            }
            
            // 1. No más de 3 números juntos
            if (/\d{4,}/.test(value)) {
                showAlert('El nombre no puede tener más de 3 números juntos');
                return;
            }
            
            // 2. No más de 2 guiones juntos ni más de 2 guiones en total
            if (/-{3,}/.test(value)) {
                showAlert('El nombre no puede tener más de 2 guiones juntos');
                return;
            }
            if ((value.match(/-/g) || []).length > 2) {
                showAlert('El nombre no puede tener más de 2 guiones en total');
                return;
            }
            
            // 2.1. No más de 2 puntos juntos ni más de 2 puntos en total
            if (/\.{3,}/.test(value)) {
                showAlert('El nombre no puede tener más de 2 puntos juntos');
                return;
            }
            if ((value.match(/\./g) || []).length > 2) {
                showAlert('El nombre no puede tener más de 2 puntos en total');
                return;
            }
            
            // 3. Validación estricta de caracteres especiales
            // Solo permitir letras, números, espacios, guiones y puntos
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ0-9\s\-\.]+$/.test(value)) {
                showAlert('El nombre solo puede contener letras, números, espacios, guiones (-) y puntos (.)');
                return;
            }
            
            // 4. No más de 3 caracteres repetidos seguidos
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El nombre no puede tener más de 3 caracteres repetidos seguidos');
                return;
            }
            
            // Validaciones adicionales
            if (value.length > 100) {
                showAlert('El nombre no puede exceder 100 caracteres');
                return;
            }
            if (value.trim() === '' && value.length > 0) {
                showAlert('El nombre no puede ser solo espacios en blanco');
                return;
            }
            if (/^\d/.test(value)) {
                showAlert('El nombre no puede comenzar con números');
                return;
            }
            if (/^\s/.test(value)) {
                showAlert('El nombre no puede comenzar con espacios');
                return;
            }
            if (/\s{2,}/.test(value)) {
                showAlert('El nombre no puede tener más de 1 espacio juntos');
                return;
            }
            if ((value.match(/\s/g) || []).length > 10) {
                showAlert('El nombre no puede tener más de 10 espacios en total');
                return;
            }
        }
        
        if (name === 'descripcion') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, descripcion: '' }));
                return;
            }
            
            // 1. No más de 4 números juntos (para permitir años)
            if (/\d{5,}/.test(value)) {
                showAlert('La descripción no puede tener más de 4 números juntos');
                return;
            }
            
            // 2. No más de 2 guiones juntos ni más de 2 guiones en total
            if (/-{3,}/.test(value)) {
                showAlert('La descripción no puede tener más de 2 guiones juntos');
                return;
            }
            if ((value.match(/-/g) || []).length > 2) {
                showAlert('La descripción no puede tener más de 2 guiones en total');
                return;
            }
            
            // 2.1. No más de 2 puntos juntos ni más de 2 puntos en total
            if (/\.{3,}/.test(value)) {
                showAlert('La descripción no puede tener más de 2 puntos juntos');
                return;
            }
            if ((value.match(/\./g) || []).length > 2) {
                showAlert('La descripción no puede tener más de 2 puntos en total');
                return;
            }
            
            // 3. Permitir caracteres especiales en descripción (más flexible)
            // Solo permitir letras, números, espacios, guiones, puntos y caracteres especiales comunes
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ0-9\s\-\.\,\;\:\!\?\"\'\(\)\[\]\{\}\/\+\=\*\&\^\%\$\#\@]+$/.test(value)) {
                showAlert('La descripción contiene caracteres no permitidos');
                return;
            }
            
            // 4. No más de 3 caracteres repetidos seguidos
            if (/(.)\1{2,}/.test(value)) {
                showAlert('La descripción no puede tener más de 3 caracteres repetidos seguidos');
                return;
            }
            
            // Validaciones adicionales
            if (value.length > 1000) {
                showAlert('La descripción no puede exceder 1000 caracteres');
                return;
            }
            if (value.trim() === '' && value.length > 0) {
                showAlert('La descripción no puede ser solo espacios en blanco');
                return;
            }
            if (/^\s/.test(value)) {
                showAlert('La descripción no puede comenzar con espacios');
                return;
            }
            if (/\s{2,}/.test(value)) {
                showAlert('La descripción no puede tener más de 1 espacio juntos');
                return;
            }
        }
        
        if (name === 'stock') {
            // Solo permitir números - si hay cualquier carácter no numérico, no actualizar
            if (!/^\d*$/.test(value)) {
                showAlert('El stock solo puede contener números');
                return; // Esto previene que se actualice el estado
            }
            
            if (value !== '') {
                const numValue = parseInt(value);
                if (isNaN(numValue) || numValue < 0) {
                    showAlert('El stock no puede ser negativo');
                    return;
                }
                if (numValue > 99999) {
                    showAlert('El stock no puede exceder 99,999 unidades');
                    return;
                }
            }
        }
        
        if (name === 'descuento') {
            // Solo permitir números - si hay cualquier carácter no numérico, no actualizar
            if (!/^\d*$/.test(value)) {
                showAlert('El descuento solo puede contener números');
                return; // Esto previene que se actualice el estado
            }
            
            if (value !== '') {
                const numValue = parseInt(value);
                if (isNaN(numValue) || numValue < 0) {
                    showAlert('El descuento no puede ser negativo');
                    return;
                }
                if (numValue > 100) {
                    showAlert('El descuento no puede exceder 100%');
                    return;
                }
            }
            
            // Si el valor está vacío, mantenerlo como string vacío
            newValue = value === '' ? '' : parseInt(value);
        }
        
        if (name === 'marca') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, marca: '' }));
                return;
            }
            
            // 1. No más de 3 números juntos
            if (/\d{4,}/.test(value)) {
                showAlert('La marca no puede tener más de 3 números juntos');
                return;
            }
            
            // 2. No más de 2 guiones juntos ni más de 2 guiones en total
            if (/-{3,}/.test(value)) {
                showAlert('La marca no puede tener más de 2 guiones juntos');
                return;
            }
            if ((value.match(/-/g) || []).length > 2) {
                showAlert('La marca no puede tener más de 2 guiones en total');
                return;
            }
            
            // 2.1. No más de 2 puntos juntos ni más de 2 puntos en total
            if (/\.{3,}/.test(value)) {
                showAlert('La marca no puede tener más de 2 puntos juntos');
                return;
            }
            if ((value.match(/\./g) || []).length > 2) {
                showAlert('La marca no puede tener más de 2 puntos en total');
                return;
            }
            
            // 3. Validación estricta de caracteres especiales
            // Solo permitir letras, números, espacios, guiones y puntos
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ0-9\s\-\.]+$/.test(value)) {
                showAlert('La marca solo puede contener letras, números, espacios, guiones (-) y puntos (.)');
                return;
            }
            
            // 4. No más de 3 caracteres repetidos seguidos
            if (/(.)\1{2,}/.test(value)) {
                showAlert('La marca no puede tener más de 3 caracteres repetidos seguidos');
                return;
            }
            
            // Validaciones adicionales
            if (value.length > 50) {
                showAlert('La marca no puede exceder 50 caracteres');
                return;
            }
            if (value.trim() === '' && value.length > 0) {
                showAlert('La marca no puede ser solo espacios en blanco');
                return;
            }
            if (/^\d/.test(value)) {
                showAlert('La marca no puede comenzar con números');
                return;
            }
            if (/^\s/.test(value)) {
                showAlert('La marca no puede comenzar con espacios');
                return;
            }
            if (/\s{2,}/.test(value)) {
                showAlert('La marca no puede tener más de 1 espacio juntos');
                return;
            }
            if ((value.match(/\s/g) || []).length > 2) {
                showAlert('La marca no puede tener más de 2 espacios en total');
                return;
            }
        }
        
        if (name === 'codigoSKU') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, codigoSKU: '' }));
                return;
            }
            // No puede tener espacios
            if (value.includes(' ')) {
                showAlert('El SKU no puede contener espacios');
                return;
            }
            // Solo letras, números, guiones y guiones bajos
            if (/[^a-zA-Z0-9\-_]/.test(value)) {
                showAlert('El SKU solo puede contener letras, números, guiones y guiones bajos');
                return;
            }
            // No más de 1 guión seguido ni en total
            if (/-{2,}/.test(value)) {
                showAlert('El SKU no puede tener más de 1 guión seguido');
                return;
            }
            if ((value.match(/-/g) || []).length > 2) {
                showAlert('El SKU no puede tener más de 2 guiones en total');
                return;
            }
            // No más de 1 guión bajo seguido ni en total
            if (/_{2,}/.test(value)) {
                showAlert('El SKU no puede tener más de 1 guión bajo seguido');
                return;
            }
            if ((value.match(/_/g) || []).length > 2) {
                showAlert('El SKU no puede tener más de 2 guiones bajos en total');
                return;
            }
            // No más de 4 letras seguidas
            if (/[a-zA-Z]{5,}/.test(value)) {
                showAlert('El SKU no puede tener más de 4 letras seguidas');
                return;
            }
            // No más de 3 números juntos
            if (/\d{4,}/.test(value)) {
                showAlert('El SKU no puede tener más de 3 números juntos');
                return;
            }
            // No puede comenzar con guión o guión bajo (permitir terminar con guión mientras se escribe)
            if (/^[-_]/.test(value)) {
                showAlert('El SKU no puede comenzar con guión o guión bajo');
                return;
            }
            // Longitud máxima 50 (quitar la mínima para permitir escribir)
            if (value.length > 50) {
                showAlert('El código SKU no puede exceder 50 caracteres');
                return;
            }
            // No solo números ni solo letras (solo si tiene al menos 5 caracteres)
            if (value.length >= 5) {
                if (/^\d+$/.test(value)) {
                    showAlert('El SKU no puede ser solo números');
                    return;
                }
                if (/^[a-zA-Z]+$/.test(value)) {
                    showAlert('El SKU no puede ser solo letras');
                    return;
                }
                // No solo caracteres repetidos
                if (/^(.)\1+$/.test(value)) {
                    showAlert('El SKU no puede ser solo caracteres repetidos');
                    return;
                }
            }
        }
        
        setFormData(prev => ({
            ...prev,
            [name]: newValue
        }));

        if (errors[name]) {
            setErrors(prev => ({
                ...prev,
                [name]: null
            }));
        }
    };

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            const validTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp'];
            if (!validTypes.includes(file.type)) {
                showAlert('Solo se permiten imágenes JPG, PNG o WebP');
                e.target.value = '';
                setImagen(null);
                setPreviewImagen(null);
                return;
            }
            
            if (file.size > 5 * 1024 * 1024) {
                showAlert('La imagen no puede exceder 5MB');
                e.target.value = '';
                setImagen(null);
                setPreviewImagen(null);
                return;
            }
            
            const img = new Image();
            img.onload = function() {
                if (this.width < 200 || this.height < 200) {
                    showAlert('La imagen debe tener al menos 200x200 píxeles');
                    e.target.value = '';
                    setImagen(null);
                    setPreviewImagen(null);
                    return;
                }
                
                if (this.width > 4000 || this.height > 4000) {
                    showAlert('La imagen no puede exceder 4000x4000 píxeles');
                    e.target.value = '';
                    setImagen(null);
                    setPreviewImagen(null);
                    return;
                }
                
                setImagen(file);
                
                if (errors.imagen) {
                    setErrors(prev => ({ ...prev, imagen: null }));
                }
                
                const reader = new FileReader();
                reader.onload = (e) => setPreviewImagen(e.target.result);
                reader.readAsDataURL(file);
            };
            
            img.onerror = function() {
                showAlert('Archivo de imagen corrupto o no válido');
                e.target.value = '';
                setImagen(null);
                setPreviewImagen(null);
            };
            
            img.src = URL.createObjectURL(file);
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        
        if (formData.descripcion.trim().length < 10) {
            showAlert('La descripción debe tener al menos 10 caracteres');
            return;
        }
        
        if (formData.codigoSKU.trim().length < 3) {
            showAlert('El código SKU debe tener al menos 3 caracteres');
            return;
        }
        
        if (formData.nombre.trim().length < 3) {
            showAlert('El nombre debe tener al menos 3 caracteres');
            return;
        }
        
        if (formData.marca.trim().length < 2) {
            showAlert('La marca debe tener al menos 2 caracteres');
            return;
        }
        
        if (!imagen) {
            showAlert('Debes seleccionar una imagen para el producto');
            return;
        }
        
        const submitFormData = new FormData();
        
        Object.keys(formData).forEach(key => {
            if (key === 'precio') {
                const rawPrice = formData[key].replace(/\D/g, '');
                submitFormData.append(key, rawPrice);
            } else if (key === 'descuento') {
                // Convertir descuento vacío a 0
                const descuentoValue = formData[key] === '' ? 0 : formData[key];
                submitFormData.append(key, descuentoValue);
            } else {
                submitFormData.append(key, formData[key]);
            }
        });
        
        if (imagen) {
            submitFormData.append('imagen', imagen);
        }

        handleCreate(submitFormData);
    };

    const handleClose = () => {
        setShow(false);
        resetForm();
    };

    if (!show) return null;

    return (
        <div className="crear-producto-overlay">
            <div className="crear-producto-modal">
                {alert && (
                    <div className="alert-notification">
                        <span>{alert}</span>
                    </div>
                )}
                
                <div className="crear-producto-header">
                    <h2>🆕 Crear Nuevo Producto</h2>
                    <button 
                        className="close-button" 
                        onClick={handleClose}
                        type="button"
                    >
                        <FaTimes />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="crear-producto-form">
                    <div className="form-grid">
                        <div className="form-section">
                            <h3>📝 Información Básica</h3>
                            
                            <div className="form-group">
                                <label htmlFor="nombre">Nombre del Producto *</label>
                                <input
                                    type="text"
                                    id="nombre"
                                    name="nombre"
                                    value={formData.nombre}
                                    onChange={handleInputChange}
                                    placeholder="Ej: Lentes Ray-Ban Aviator Clásicos"
                                    className={errors.nombre ? 'error' : ''}
                                    maxLength={100}
                                />
                                {errors.nombre && <span className="error-message">{errors.nombre}</span>}
                            </div>

                            <div className="form-group">
                                <label htmlFor="descripcion">Descripción *</label>
                                <textarea
                                    id="descripcion"
                                    name="descripcion"
                                    value={formData.descripcion}
                                    onChange={handleInputChange}
                                    placeholder="Descripción detallada del producto, características, materiales, etc."
                                    className={errors.descripcion ? 'error' : ''}
                                    rows={4}
                                    maxLength={1000}
                                />
                                <small className="char-counter">{formData.descripcion.length}/1000</small>
                                {errors.descripcion && <span className="error-message">{errors.descripcion}</span>}
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="marca">Marca *</label>
                                    <input
                                        type="text"
                                        id="marca"
                                        name="marca"
                                        value={formData.marca}
                                        onChange={handleInputChange}
                                        placeholder="Ej: Ray-Ban"
                                        className={errors.marca ? 'error' : ''}
                                    />
                                    {errors.marca && <span className="error-message">{errors.marca}</span>}
                                </div>

                                <div className="form-group">
                                    <label htmlFor="codigoSKU">Código SKU *</label>
                                    <input
                                        type="text"
                                        id="codigoSKU"
                                        name="codigoSKU"
                                        value={formData.codigoSKU}
                                        onChange={handleInputChange}
                                        placeholder="Ej: RB-3025-001"
                                        className={errors.codigoSKU ? 'error' : ''}
                                    />
                                    {errors.codigoSKU && <span className="error-message">{errors.codigoSKU}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>🏷️ Precio y Categoría</h3>
                            
                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="precio">Precio (CLP) *</label>
                                    <input
                                        type="text"
                                        id="precio"
                                        name="precio"
                                        value={formData.precio}
                                        onChange={handlePriceChange}
                                        placeholder="149.990"
                                        className={errors.precio ? 'error' : ''}
                                    />
                                    {formData.precio && (
                                        <small className="precio-formateado">
                                            Precio: ${formData.precio} CLP
                                        </small>
                                    )}
                                    {errors.precio && <span className="error-message">{errors.precio}</span>}
                                </div>

                                <div className="form-group">
                                    <label>Categoría y Subcategoría *</label>
                                    <DropdownCategorias
                                        selectedCategoria={formData.categoria}
                                        selectedSubcategoria={formData.subcategoria}
                                        onCategoriaChange={(categoria) => setFormData(prev => ({ ...prev, categoria, subcategoria: '' }))}
                                        onSubcategoriaChange={(subcategoria) => setFormData(prev => ({ ...prev, subcategoria }))}
                                        className={errors.categoria || errors.subcategoria ? 'error' : ''}
                                        dropdownActivo={dropdownActivo}
                                        setDropdownActivo={setDropdownActivo}
                                        id="crear-producto"
                                    />
                                    {errors.categoria && <span className="error-message">{errors.categoria}</span>}
                                    {errors.subcategoria && <span className="error-message">{errors.subcategoria}</span>}
                                </div>
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="stock">Stock *</label>
                                    <input
                                        type="number"
                                        id="stock"
                                        name="stock"
                                        value={formData.stock}
                                        onChange={handleInputChange}
                                        placeholder="50"
                                        min="0"
                                        max="99999"
                                        inputMode="numeric"
                                        className={errors.stock ? 'error' : ''}
                                        onKeyPress={(e) => {
                                            if (!/[0-9]/.test(e.key)) {
                                                e.preventDefault();
                                            }
                                        }}
                                        onInput={(e) => {
                                            // Validación adicional para prevenir pegar texto
                                            const value = e.target.value;
                                            if (!/^\d*$/.test(value)) {
                                                e.target.value = value.replace(/\D/g, '');
                                                showAlert('El stock solo puede contener números');
                                            }
                                        }}
                                        onPaste={(e) => {
                                            e.preventDefault();
                                            const pastedText = (e.clipboardData || window.clipboardData).getData('text');
                                            const numbersOnly = pastedText.replace(/\D/g, '');
                                            e.target.value = numbersOnly;
                                            // Forzar la actualización del estado
                                            setFormData(prev => ({ ...prev, stock: numbersOnly }));
                                        }}
                                        onDrop={(e) => {
                                            e.preventDefault();
                                        }}
                                    />
                                    {errors.stock && <span className="error-message">{errors.stock}</span>}
                                </div>

                                <div className="form-group">
                                    <label htmlFor="descuento">Descuento (%)</label>
                                    <input
                                        type="number"
                                        id="descuento"
                                        name="descuento"
                                        value={formData.descuento === 0 || formData.descuento === '' ? '' : formData.descuento}
                                        onChange={handleInputChange}
                                        placeholder="0"
                                        min="0"
                                        max="100"
                                        inputMode="numeric"
                                        className={errors.descuento ? 'error' : ''}
                                        onKeyPress={(e) => {
                                            if (!/[0-9]/.test(e.key)) {
                                                e.preventDefault();
                                            }
                                        }}
                                        onInput={(e) => {
                                            // Validación adicional para prevenir pegar texto
                                            const value = e.target.value;
                                            if (!/^\d*$/.test(value)) {
                                                e.target.value = value.replace(/\D/g, '');
                                                showAlert('El descuento solo puede contener números');
                                            }
                                        }}
                                        onPaste={(e) => {
                                            e.preventDefault();
                                            const pastedText = (e.clipboardData || window.clipboardData).getData('text');
                                            const numbersOnly = pastedText.replace(/\D/g, '');
                                            e.target.value = numbersOnly;
                                            // Forzar la actualización del estado
                                            setFormData(prev => ({ ...prev, descuento: numbersOnly }));
                                        }}
                                        onDrop={(e) => {
                                            e.preventDefault();
                                        }}
                                    />
                                    {errors.descuento && <span className="error-message">{errors.descuento}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>📷 Imagen del Producto</h3>
                            
                            <div className="image-upload-section">
                                <div 
                                    className={`image-upload-area ${errors.imagen ? 'error' : ''}`}
                                    onClick={() => fileInputRef.current?.click()}
                                >
                                    {previewImagen ? (
                                        <div className="image-preview">
                                            <img src={previewImagen} alt="Preview" />
                                            <div className="image-overlay">
                                                <FaImage size={24} />
                                                <span>Cambiar imagen</span>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="upload-placeholder">
                                            <FaUpload size={48} />
                                            <h4>Subir imagen del producto</h4>
                                            <p>JPG, PNG o WebP • Máximo 5MB</p>
                                            <p>Recomendado: 800x600px</p>
                                        </div>
                                    )}
                                </div>
                                
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    accept="image/jpeg,image/jpg,image/png,image/webp"
                                    onChange={handleImageChange}
                                    style={{ display: 'none' }}
                                />
                                
                                {errors.imagen && <span className="error-message">{errors.imagen}</span>}
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>⚙️ Configuración</h3>
                            
                            <div className="checkbox-group">
                                <label className="checkbox-label">
                                    <input
                                        type="checkbox"
                                        name="activo"
                                        checked={formData.activo}
                                        onChange={handleInputChange}
                                    />
                                    <span className="checkbox-custom"></span>
                                    Producto activo (visible en la tienda)
                                </label>

                                <label className="checkbox-label">
                                    <input
                                        type="checkbox"
                                        name="oferta"
                                        checked={formData.oferta}
                                        onChange={handleInputChange}
                                    />
                                    <span className="checkbox-custom"></span>
                                    Producto en oferta
                                </label>
                            </div>
                        </div>
                    </div>

                    <div className="form-actions">
                        <button
                            type="button"
                            onClick={handleClose}
                            className="btn-cancel"
                            disabled={loading}
                        >
                            Cancelar
                        </button>
                        <button
                            type="submit"
                            className="btn-create"
                            disabled={loading || !isFormValid()}
                        >
                            {loading ? (
                                <>
                                    <FaSpinner className="spinner" />
                                    Creando producto...
                                </>
                            ) : (
                                'Crear Producto'
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default CrearProductoPopup;

import { useState, useEffect } from 'react';
import { FaTimes, FaUser, FaEnvelope, FaIdCard, FaPhone, FaCalendar, FaLock, FaEye, FaEyeSlash, FaSpinner } from 'react-icons/fa';
import useCreateUser from '@hooks/users/useCreateUser';
import { validationRules } from '@helpers/validation.helper';
import { formatRut, formatTelefono } from '@helpers/formatData';
import DatePicker from './DatePicker';
import '@styles/crearUsuario.css';

const CrearUsuarioPopup = ({ show, setShow, onUsuarioCreated }) => {
    const { handleCreateUser, loading } = useCreateUser();
    
    const [formData, setFormData] = useState({
        primerNombre: '',
        segundoNombre: '',
        apellidoPaterno: '',
        apellidoMaterno: '',
        rut: '',
        email: '',
        password: '',
        confirmPassword: '',
        telefono: '',
        fechaNacimiento: '',
        genero: '',
        rol: 'usuario'
    });

    const [errors, setErrors] = useState({});
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    const [alert, setAlert] = useState(null);

    useEffect(() => {
        if (show) {
            document.body.classList.add('no-scroll');
        } else {
            document.body.classList.remove('no-scroll');
        }

        return () => {
            document.body.classList.remove('no-scroll');
        };
    }, [show]);

    const showAlert = (message) => {
        setAlert(message);
        setTimeout(() => setAlert(null), 2000);
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        let newValue = value;
        
        // Validaciones específicas durante la escritura
        if (name === 'rut') {
            // Solo permitir números y K
            if (!/^[0-9kK\.\-]*$/.test(value)) {
                showAlert('El RUT solo puede contener números y la letra K');
                return;
            }
            newValue = formatRut(value);
        } else if (name === 'telefono') {
            // Solo permitir números y el símbolo +
            if (!/^[\+\d\s]*$/.test(value)) {
                showAlert('El teléfono solo puede contener números y el símbolo +');
                return;
            }
            newValue = value.replace(/[^\+\d]/g, '');
        } else if (['primerNombre', 'apellidoPaterno'].includes(name)) {
            // Validaciones para nombres sin espacios
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ]*$/.test(value)) {
                showAlert('Los nombres solo pueden contener letras (sin espacios)');
                return;
            }
            
            // No permitir espacios
            if (/\s/.test(value)) {
                showAlert('El nombre no puede contener espacios');
                return;
            }
            
            // No permitir completamente en mayúsculas
            if (value === value.toUpperCase() && value.length > 1) {
                showAlert('El nombre no puede estar completamente en mayúsculas');
                return;
            }
            
            // Validar mayúsculas correctas (solo si tiene más de 1 carácter)
            if (value.length > 1) {
                // La primera letra debe ser mayúscula
                if (value[0] !== value[0].toUpperCase()) {
                    showAlert('El nombre debe tener mayúscula al inicio');
                    return;
                }
                // El resto debe ser minúscula
                if (value.slice(1) !== value.slice(1).toLowerCase()) {
                    showAlert('El nombre solo debe tener mayúscula al inicio');
                    return;
                }
            }
            
            // No más de 2 letras iguales consecutivas
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El nombre no puede tener más de 2 letras iguales consecutivas');
                return;
            }
            
            // Limitar longitud
            if (value.length > 50) {
                showAlert('El nombre no puede exceder 50 caracteres');
                return;
            }
        } else if (name === 'segundoNombre') {
            // Validaciones para segundo nombre (puede tener 1 espacio)
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ\s]*$/.test(value)) {
                showAlert('El segundo nombre solo puede contener letras y espacios');
                return;
            }
            
            // No permitir más de 1 espacio consecutivo
            if (/\s{2,}/.test(value)) {
                showAlert('No se permiten más de 1 espacio consecutivo');
                return;
            }
            
            // No permitir empezar con espacio
            if (/^\s/.test(value) && value.length === 1) {
                showAlert('El segundo nombre no puede empezar con un espacio');
                return;
            }
            
            // No permitir completamente en mayúsculas
            if (value === value.toUpperCase() && value.length > 1) {
                showAlert('El segundo nombre no puede estar completamente en mayúsculas');
                return;
            }
            
            // Validar mayúsculas correctas (solo si tiene más de 1 carácter)
            if (value.length > 1) {
                const words = value.split(' ');
                for (let i = 0; i < words.length; i++) {
                    const word = words[i];
                    if (word.length > 0) {
                        // La primera letra debe ser mayúscula
                        if (word[0] !== word[0].toUpperCase()) {
                            showAlert('El segundo nombre debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                        // El resto debe ser minúscula
                        if (word.length > 1 && word.slice(1) !== word.slice(1).toLowerCase()) {
                            showAlert('El segundo nombre solo debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                    }
                }
            }
            
            // No más de 2 letras iguales consecutivas
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El segundo nombre no puede tener más de 2 letras iguales consecutivas');
                return;
            }
            
            // Limitar longitud
            if (value.length > 50) {
                showAlert('El segundo nombre no puede exceder 50 caracteres');
                return;
            }
        } else if (name === 'apellidoMaterno') {
            // Validaciones para apellido materno (hasta 2 espacios)
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ\s]*$/.test(value)) {
                showAlert('El apellido materno solo puede contener letras y espacios');
                return;
            }
            
            // No permitir más de 1 espacio consecutivo
            if (/\s{2,}/.test(value)) {
                showAlert('No se permiten más de 1 espacio consecutivo');
                return;
            }
            
            // No permitir empezar con espacio
            if (/^\s/.test(value) && value.length === 1) {
                showAlert('El apellido materno no puede empezar con un espacio');
                return;
            }
            
            // No permitir completamente en mayúsculas
            if (value === value.toUpperCase() && value.length > 1) {
                showAlert('El apellido materno no puede estar completamente en mayúsculas');
                return;
            }
            
            // Validar mayúsculas correctas (solo si tiene más de 1 carácter)
            if (value.length > 1) {
                const words = value.split(' ');
                for (let i = 0; i < words.length; i++) {
                    const word = words[i];
                    if (word.length > 0) {
                        // La primera letra debe ser mayúscula
                        if (word[0] !== word[0].toUpperCase()) {
                            showAlert('El apellido materno debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                        // El resto debe ser minúscula
                        if (word.length > 1 && word.slice(1) !== word.slice(1).toLowerCase()) {
                            showAlert('El apellido materno solo debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                    }
                }
            }
            
            // No más de 2 letras iguales consecutivas
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El apellido materno no puede tener más de 2 letras iguales consecutivas');
                return;
            }
            
            // Limitar longitud
            if (value.length > 50) {
                showAlert('El apellido materno no puede exceder 50 caracteres');
                return;
            }
        } else if (name === 'email') {
            // Básicamente no validar durante escritura, solo al enviar
            newValue = value.toLowerCase();
        }
        
        setFormData(prev => ({ ...prev, [name]: newValue }));
        
        // Limpiar error al escribir
        if (errors[name]) {
            setErrors(prev => ({ ...prev, [name]: '' }));
        }
    };

    const isFormValid = () => {
        return (
            formData.primerNombre.trim().length >= 2 &&
            formData.apellidoPaterno.trim().length >= 2 &&
            formData.rut.trim().length >= 11 &&
            formData.email.trim().length >= 5 &&
            formData.password.length >= 6 &&
            formData.confirmPassword.length >= 6 &&
            formData.password === formData.confirmPassword
        );
    };

    const validateForm = () => {
        const newErrors = {};

        // Validar primer nombre
        const primerNombreError = validationRules.nombre(formData.primerNombre, 'Primer nombre');
        if (primerNombreError || !formData.primerNombre.trim()) {
            newErrors.primerNombre = primerNombreError || 'El primer nombre es requerido';
        }

        // Validar segundo nombre (opcional)
        if (formData.segundoNombre.trim()) {
            const segundoNombreError = validationRules.segundoNombre(formData.segundoNombre, 'Segundo nombre');
            if (segundoNombreError) {
                newErrors.segundoNombre = segundoNombreError;
            }
        }

        // Validar apellido paterno
        const apellidoPaternoError = validationRules.apellidoPaterno(formData.apellidoPaterno, 'Apellido paterno');
        if (apellidoPaternoError || !formData.apellidoPaterno.trim()) {
            newErrors.apellidoPaterno = apellidoPaternoError || 'El apellido paterno es requerido';
        }

        // Validar apellido materno (opcional)
        if (formData.apellidoMaterno.trim()) {
            const apellidoMaternoError = validationRules.apellidoMaterno(formData.apellidoMaterno, 'Apellido materno');
            if (apellidoMaternoError) {
                newErrors.apellidoMaterno = apellidoMaternoError;
            }
        }

        // Validar RUT
        const rutError = validationRules.rut(formData.rut);
        if (rutError) {
            newErrors.rut = rutError;
        }

        // Validar email
        const emailError = validationRules.email(formData.email);
        if (emailError || !formData.email.trim()) {
            newErrors.email = emailError || 'El email es requerido';
        }

        // Validar contraseña
        if (!formData.password.trim()) {
            newErrors.password = 'La contraseña es requerida';
        } else {
            const passwordError = validationRules.password(formData.password);
            if (passwordError) {
                newErrors.password = passwordError;
            }
        }

        // Validar confirmación de contraseña
        if (!formData.confirmPassword.trim()) {
            newErrors.confirmPassword = 'Confirmar contraseña es requerido';
        } else if (formData.password !== formData.confirmPassword) {
            newErrors.confirmPassword = 'Las contraseñas no coinciden';
        }

        // Validar teléfono (opcional)
        if (formData.telefono.trim()) {
            const telefonoError = validationRules.telefonoChileno(formData.telefono);
            if (telefonoError) {
                newErrors.telefono = telefonoError;
            }
        }

        // Validar fecha de nacimiento (opcional)
        if (formData.fechaNacimiento) {
            const fechaError = validationRules.fechaNacimiento(formData.fechaNacimiento);
            if (fechaError) {
                newErrors.fechaNacimiento = fechaError;
            }
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const resetForm = () => {
        setFormData({
            primerNombre: '',
            segundoNombre: '',
            apellidoPaterno: '',
            apellidoMaterno: '',
            rut: '',
            email: '',
            password: '',
            confirmPassword: '',
            telefono: '',
            fechaNacimiento: '',
            genero: '',
            rol: 'usuario'
        });
        setErrors({});
        setAlert(null);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (!validateForm()) {
            showAlert('Por favor, corrige los errores en el formulario');
            return;
        }

        const userData = {
            primerNombre: formData.primerNombre.trim(),
            segundoNombre: formData.segundoNombre.trim() || null,
            apellidoPaterno: formData.apellidoPaterno.trim(),
            apellidoMaterno: formData.apellidoMaterno.trim() || null,
            rut: formData.rut.trim(),
            email: formData.email.trim().toLowerCase(),
            password: formData.password,
            telefono: formData.telefono.trim() || null,
            fechaNacimiento: formData.fechaNacimiento || null,
            genero: formData.genero || null,
            rol: formData.rol
        };

        const result = await handleCreateUser(userData);
        
        if (result.success) {
            onUsuarioCreated();
            handleClose();
        } else if (result.field) {
            setErrors(prev => ({ ...prev, [result.field]: result.error }));
        } else {
            showAlert(result.error || 'Error al crear el usuario');
        }
    };

    const handleClose = () => {
        setShow(false);
        resetForm();
    };

    if (!show) return null;

    return (
        <div className="crear-usuario-overlay">
            <div className="crear-usuario-modal">
                {alert && (
                    <div className="alert-notification">
                        <span>{alert}</span>
                    </div>
                )}
                
                <div className="crear-usuario-header">
                    <h2>👤 Crear Nuevo Usuario</h2>
                    <button 
                        className="close-button" 
                        onClick={handleClose}
                        type="button"
                        disabled={loading}
                    >
                        <FaTimes />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="crear-usuario-form">
                    <div className="usuario-form-grid">
                        <div className="form-section">
                            <h3>📝 Información Personal</h3>
                            
                        <div className="form-row">
                            <div className="form-group">
                                    <label htmlFor="primerNombre">Primer Nombre *</label>
                                <input
                                    type="text"
                                    id="primerNombre"
                                    name="primerNombre"
                                    value={formData.primerNombre}
                                    onChange={handleInputChange}
                                    className={errors.primerNombre ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: Juan"
                                        maxLength={50}
                                />
                                {errors.primerNombre && <span className="error-message">{errors.primerNombre}</span>}
                            </div>

                            <div className="form-group">
                                    <label htmlFor="segundoNombre">Segundo Nombre</label>
                                <input
                                    type="text"
                                    id="segundoNombre"
                                    name="segundoNombre"
                                    value={formData.segundoNombre}
                                    onChange={handleInputChange}
                                        className={errors.segundoNombre ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: Carlos (opcional)"
                                        maxLength={50}
                                />
                                    {errors.segundoNombre && <span className="error-message">{errors.segundoNombre}</span>}
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                    <label htmlFor="apellidoPaterno">Apellido Paterno *</label>
                                <input
                                    type="text"
                                    id="apellidoPaterno"
                                    name="apellidoPaterno"
                                    value={formData.apellidoPaterno}
                                    onChange={handleInputChange}
                                    className={errors.apellidoPaterno ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: Pérez"
                                        maxLength={50}
                                />
                                {errors.apellidoPaterno && <span className="error-message">{errors.apellidoPaterno}</span>}
                            </div>

                            <div className="form-group">
                                    <label htmlFor="apellidoMaterno">Apellido Materno</label>
                                <input
                                    type="text"
                                    id="apellidoMaterno"
                                    name="apellidoMaterno"
                                    value={formData.apellidoMaterno}
                                    onChange={handleInputChange}
                                        className={errors.apellidoMaterno ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: González (opcional)"
                                        maxLength={50}
                                />
                                    {errors.apellidoMaterno && <span className="error-message">{errors.apellidoMaterno}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>🆔 Identificación y Contacto</h3>

                        <div className="form-row">
                            <div className="form-group">
                                <label htmlFor="rut">
                                    <FaIdCard className="label-icon" />
                                    RUT *
                                </label>
                                <input
                                    type="text"
                                    id="rut"
                                    name="rut"
                                    value={formData.rut}
                                    onChange={handleInputChange}
                                    className={errors.rut ? 'error' : ''}
                                    disabled={loading}
                                    placeholder="12.345.678-9"
                                        maxLength={12}
                                />
                                    {formData.rut && (
                                        <small className="rut-formatted">
                                            RUT: {formData.rut}
                                        </small>
                                    )}
                                {errors.rut && <span className="error-message">{errors.rut}</span>}
                            </div>

                            <div className="form-group">
                                <label htmlFor="email">
                                    <FaEnvelope className="label-icon" />
                                    Email *
                                </label>
                                <input
                                    type="email"
                                    id="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleInputChange}
                                    className={errors.email ? 'error' : ''}
                                    disabled={loading}
                                    placeholder="usuario@ejemplo.com"
                                        maxLength={100}
                                />
                                {errors.email && <span className="error-message">{errors.email}</span>}
                            </div>
                        </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="telefono">
                                        <FaPhone className="label-icon" />
                                        Teléfono
                                    </label>
                                    <input
                                        type="tel"
                                        id="telefono"
                                        name="telefono"
                                        value={formData.telefono}
                                        onChange={handleInputChange}
                                        className={errors.telefono ? 'error' : ''}
                                        disabled={loading}
                                        placeholder="+56912345678"
                                        maxLength={15}
                                    />
                                    {formData.telefono && (
                                        <small className="telefono-formatted">
                                            Teléfono: {formatTelefono(formData.telefono)}
                                        </small>
                                    )}
                                    {errors.telefono && <span className="error-message">{errors.telefono}</span>}
                                </div>

                                <div className="form-group">
                                    <label htmlFor="fechaNacimiento">
                                        <FaCalendar className="label-icon" />
                                        Fecha de Nacimiento
                                    </label>
                                    <DatePicker
                                        value={formData.fechaNacimiento}
                                        onChange={(value) => {
                                            setFormData(prev => ({ ...prev, fechaNacimiento: value }));
                                            if (errors.fechaNacimiento) {
                                                setErrors(prev => ({ ...prev, fechaNacimiento: '' }));
                                            }
                                        }}
                                        placeholder="Seleccionar fecha"
                                        disabled={loading}
                                    />
                                    {errors.fechaNacimiento && <span className="error-message">{errors.fechaNacimiento}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>🔐 Seguridad</h3>

                        <div className="form-row">
                            <div className="form-group">
                                <label htmlFor="password">
                                    <FaLock className="label-icon" />
                                    Contraseña *
                                </label>
                                <div className="password-input-container">
                                    <input
                                        type={showPassword ? 'text' : 'password'}
                                        id="password"
                                        name="password"
                                        value={formData.password}
                                        onChange={handleInputChange}
                                        className={errors.password ? 'error' : ''}
                                        disabled={loading}
                                        placeholder="Mínimo 6 caracteres"
                                            maxLength={50}
                                    />
                                    <button
                                        type="button"
                                        className="password-toggle"
                                        onClick={() => setShowPassword(!showPassword)}
                                    >
                                        {showPassword ? <FaEyeSlash /> : <FaEye />}
                                    </button>
                                </div>
                                {errors.password && <span className="error-message">{errors.password}</span>}
                            </div>

                            <div className="form-group">
                                <label htmlFor="confirmPassword">
                                    <FaLock className="label-icon" />
                                    Confirmar Contraseña *
                                </label>
                                <div className="password-input-container">
                                    <input
                                        type={showConfirmPassword ? 'text' : 'password'}
                                        id="confirmPassword"
                                        name="confirmPassword"
                                        value={formData.confirmPassword}
                                        onChange={handleInputChange}
                                        className={errors.confirmPassword ? 'error' : ''}
                                        disabled={loading}
                                        placeholder="Confirme la contraseña"
                                            maxLength={50}
                                    />
                                    <button
                                        type="button"
                                        className="password-toggle"
                                        onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                    >
                                        {showConfirmPassword ? <FaEyeSlash /> : <FaEye />}
                                    </button>
                                </div>
                                {errors.confirmPassword && <span className="error-message">{errors.confirmPassword}</span>}
                            </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>⚙️ Configuración</h3>

                        <div className="form-row">
                            <div className="form-group">
                                    <label htmlFor="genero">Género</label>
                                <select
                                    id="genero"
                                    name="genero"
                                    value={formData.genero}
                                    onChange={handleInputChange}
                                    disabled={loading}
                                >
                                    <option value="">Seleccionar género</option>
                                    <option value="masculino">Masculino</option>
                                    <option value="femenino">Femenino</option>
                                    <option value="otro">Otro</option>
                                    <option value="no especificar">Prefiero no especificar</option>
                                </select>
                            </div>

                            <div className="form-group">
                                    <label htmlFor="rol">Rol *</label>
                                <select
                                    id="rol"
                                    name="rol"
                                    value={formData.rol}
                                    onChange={handleInputChange}
                                    disabled={loading}
                                >
                                    <option value="usuario">Usuario</option>
                                    <option value="administrador">Administrador</option>
                                </select>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="form-actions">
                        <button 
                            type="button" 
                            onClick={handleClose}
                            className="btn-cancel"
                            disabled={loading}
                        >
                            Cancelar
                        </button>
                        <button 
                            type="submit" 
                            className="btn-create"
                            disabled={loading || !isFormValid()}
                        >
                            {loading ? (
                                <>
                                    <FaSpinner className="spinner" />
                                    Creando usuario...
                                </>
                            ) : (
                                'Crear Usuario'
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default CrearUsuarioPopup;

import { useState } from 'react';
import { FaChevronDown, FaChevronUp } from 'react-icons/fa';
import { getCategoriasList, getSubcategoriasList } from '../constants/categorias.js';
import '@styles/dropdownCategorias.css';

const DropdownCategorias = ({ 
    selectedCategoria, 
    selectedSubcategoria, 
    onCategoriaChange, 
    onSubcategoriaChange,
    showSubcategories = true,
    placeholder = "Seleccionar categoría",
    dropdownActivo,
    setDropdownActivo,
    id = 'default'
}) => {
    const categoriaId = `categorias-${id}`;
    const subcategoriaId = `subcategorias-${id}`;
    const isOpen = dropdownActivo === categoriaId;
    const isSubOpen = dropdownActivo === subcategoriaId;

    const categorias = getCategoriasList();
    const subcategorias = selectedCategoria ? getSubcategoriasList(selectedCategoria) : [];
    
    const categoriaInfo = categorias.find(cat => cat.value === selectedCategoria);
    const subcategoriaInfo = subcategorias.find(sub => sub.value === selectedSubcategoria);

    const handleCategoriaSelect = (valor) => {
        onCategoriaChange(valor);
        if (valor !== selectedCategoria) {
            onSubcategoriaChange('');
        }
        setDropdownActivo(null);
    };

    const handleSubcategoriaSelect = (valor) => {
        onSubcategoriaChange(valor);
        setDropdownActivo(null);
    };

    const limpiarSeleccion = () => {
        onCategoriaChange('');
        onSubcategoriaChange('');
        setDropdownActivo(null);
    };

    return (
        <div className="dropdown-categorias">
            <div className="categoria-principal">
                <button
                    type="button"
                    className={`dropdown-btn ${selectedCategoria ? 'selected' : ''}`}
                    onClick={() => setDropdownActivo(isOpen ? null : categoriaId)}
                >
                    <div className="btn-content">
                        {categoriaInfo ? (
                            <>
                                <span className="categoria-icono">{categoriaInfo.icon}</span>
                                <span className="categoria-texto">{categoriaInfo.label}</span>
                            </>
                        ) : (
                            <span className="placeholder-texto">{placeholder}</span>
                        )}
                    </div>
                    {isOpen ? <FaChevronUp /> : <FaChevronDown />}
                </button>

                {isOpen && (
                    <div className="dropdown-menu">
                        <div className="dropdown-header">
                            <h4>Categorías</h4>
                            {selectedCategoria && (
                                <button 
                                    type="button"
                                    className="limpiar-btn"
                                    onClick={limpiarSeleccion}
                                >
                                    Limpiar
                                </button>
                            )}
                        </div>
                        
                        <div className="categorias-grid">
                            {categorias.map((cat) => (
                                <button
                                    key={cat.value}
                                    type="button"
                                    className={`categoria-item ${selectedCategoria === cat.value ? 'active' : ''}`}
                                    onClick={() => handleCategoriaSelect(cat.value)}
                                >
                                    <span className="categoria-icono">{cat.icon}</span>
                                    <span className="categoria-nombre">{cat.label}</span>
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {showSubcategories && selectedCategoria && subcategorias.length > 0 && (
                <div className="subcategoria-secundaria">
                    <button
                        type="button"
                        className={`dropdown-btn subcategoria-btn ${selectedSubcategoria ? 'selected' : ''}`}
                        onClick={() => setDropdownActivo(isSubOpen ? null : subcategoriaId)}
                    >
                        <div className="btn-content">
                            {subcategoriaInfo ? (
                                <span className="subcategoria-texto">{subcategoriaInfo.label}</span>
                            ) : (
                                <span className="placeholder-texto">Subcategoría</span>
                            )}
                        </div>
                        {isSubOpen ? <FaChevronUp /> : <FaChevronDown />}
                    </button>

                    {isSubOpen && (
                        <div className="dropdown-menu subcategoria-menu">
                            <div className="dropdown-header">
                                <h4>Subcategorías</h4>
                                {selectedSubcategoria && (
                                                                    <button 
                                    type="button"
                                    className="limpiar-btn"
                                    onClick={() => {
                                        onSubcategoriaChange('');
                                        setDropdownActivo(null);
                                    }}
                                >
                                    Limpiar
                                </button>
                                )}
                            </div>
                            
                            <div className="subcategorias-list">
                                {subcategorias.map((sub) => (
                                    <button
                                        key={sub.value}
                                        type="button"
                                        className={`subcategoria-item ${selectedSubcategoria === sub.value ? 'active' : ''}`}
                                        onClick={() => handleSubcategoriaSelect(sub.value)}
                                    >
                                        <div className="subcategoria-info">
                                            <span className="subcategoria-nombre">{sub.label}</span>
                                        </div>
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default DropdownCategorias;

import { useState, useRef, useEffect } from 'react';
import useEditProducto from '@hooks/productos/useEditProducto';
import { FaTimes, FaUpload, FaImage, FaSpinner } from 'react-icons/fa';
import DropdownCategorias from './DropdownCategorias';
import '@styles/crearProducto.css';

const EditarProductoPopup = ({ show, setShow, producto, onProductoUpdated }) => {
    const { handleEdit, loading, errors, clearErrors, setErrors } = useEditProducto((productoActualizado) => {
        setShow(false);
        if (onProductoUpdated) onProductoUpdated(productoActualizado);
    });

    const [formData, setFormData] = useState({
        nombre: '',
        descripcion: '',
        precio: '',
        categoria: '',
        subcategoria: '',
        stock: '',
        marca: '',
        codigoSKU: '',
        activo: true,
        oferta: false,
        descuento: 0
    });

    const [imagen, setImagen] = useState(null);
    const [previewImagen, setPreviewImagen] = useState(null);
    const [alert, setAlert] = useState(null);
    const [dropdownActivo, setDropdownActivo] = useState(null);
    const fileInputRef = useRef(null);

    useEffect(() => {
        if (show) {
            document.body.classList.add('no-scroll');
        } else {
            document.body.classList.remove('no-scroll');
        }

        return () => {
            document.body.classList.remove('no-scroll');
        };
    }, [show]);

    useEffect(() => {
        if (producto && show) {
            const precio = producto.precio ? producto.precio.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.') : '';
            
            setFormData({
                nombre: producto.nombre || '',
                descripcion: producto.descripcion || '',
                precio: precio,
                categoria: producto.categoria || '',
                subcategoria: producto.subcategoria || '',
                stock: producto.stock?.toString() || '',
                marca: producto.marca || '',
                codigoSKU: producto.codigoSKU || '',
                activo: producto.activo !== undefined ? producto.activo : true,
                oferta: producto.oferta !== undefined ? producto.oferta : false,
                descuento: producto.descuento || 0
            });
            
            if (producto.imagen_url) {
                setPreviewImagen(producto.imagen_url);
            }
        }
    }, [producto, show]);

    const showAlert = (message) => {
        setAlert(message);
        setTimeout(() => setAlert(null), 2000);
    };

    const isFormValid = () => {
        return (
            formData.nombre.trim().length >= 3 &&
            formData.descripcion.trim().length >= 10 &&
            formData.precio.length > 0 &&
            formData.categoria !== '' &&
            formData.subcategoria !== '' &&
            formData.stock !== '' &&
            formData.marca.trim().length >= 2 &&
            formData.codigoSKU.trim().length >= 3
        );
    };

    const formatPrice = (value) => {
        if (!value) return '';
        const number = value.toString().replace(/\D/g, '');
        return number.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    };

    const handlePriceChange = (e) => {
        const inputValue = e.target.value;
        
        if (/[a-zA-Z]/.test(inputValue)) {
            showAlert('El precio no puede contener letras');
            return;
        }
        
        if (/[^0-9.]/.test(inputValue) && inputValue !== '') {
            showAlert('El precio solo puede contener números');
            return;
        }
        
        if ((inputValue.match(/\./g) || []).length > 1) {
            showAlert('El precio no puede tener múltiples puntos decimales');
            return;
        }
        
        if (inputValue.startsWith('.')) {
            showAlert('El precio no puede comenzar con un punto decimal');
            return;
        }
        
        const rawValue = inputValue.replace(/\D/g, '');
        
        if (rawValue.length > 8) {
            showAlert('El precio es demasiado largo');
            return;
        }
        
        const actualPrice = parseInt(rawValue);
        if (rawValue && actualPrice <= 0) {
            showAlert('El precio debe ser mayor a 0');
            return;
        }
        
        if (rawValue && actualPrice > 10000000) {
            showAlert('El precio no puede exceder $10.000.000');
            return;
        }
        
        const formattedValue = formatPrice(rawValue);
        
        setFormData(prev => ({
            ...prev,
            precio: formattedValue
        }));

        if (errors.precio) {
            setErrors(prev => ({
                ...prev,
                precio: null
            }));
        }
    };

    const handleInputChange = (e) => {
        const { name, value, type, checked } = e.target;
        let newValue = type === 'checkbox' ? checked : value;
        
        if (name === 'precio') {
            handlePriceChange(e);
            return;
        }
        
        if (name === 'stock') {
            // Solo permitir números - si hay cualquier carácter no numérico, no actualizar
            if (!/^\d*$/.test(value)) {
                showAlert('El stock solo puede contener números');
                return; // Esto previene que se actualice el estado
            }
            
            if (value !== '') {
                const numValue = parseInt(value);
                if (isNaN(numValue) || numValue < 0) {
                    showAlert('El stock no puede ser negativo');
                    return;
                }
                if (numValue > 99999) {
                    showAlert('El stock no puede exceder 99,999 unidades');
                    return;
                }
            }
        }
        
        if (name === 'descuento') {
            // Solo permitir números - si hay cualquier carácter no numérico, no actualizar
            if (!/^\d*$/.test(value)) {
                showAlert('El descuento solo puede contener números');
                return; // Esto previene que se actualice el estado
            }
            
            if (value !== '') {
                const numValue = parseInt(value);
                if (isNaN(numValue) || numValue < 0) {
                    showAlert('El descuento no puede ser negativo');
                    return;
                }
                if (numValue > 100) {
                    showAlert('El descuento no puede exceder 100%');
                    return;
                }
            }
            
            // Si el valor está vacío, mantenerlo como string vacío
            newValue = value === '' ? '' : parseInt(value);
        }
        
        // Validaciones específicas para cada campo (copiadas de CrearProductoPopup)
        if (name === 'nombre') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, nombre: '' }));
                return;
            }
            
            // 1. No más de 4 números juntos
            if (/\d{5,}/.test(value)) {
                showAlert('El nombre no puede tener más de 4 números juntos');
                return;
            }
            
            // 2. No más de 2 guiones juntos ni más de 2 guiones en total
            if (/-{3,}/.test(value)) {
                showAlert('El nombre no puede tener más de 2 guiones juntos');
                return;
            }
            if ((value.match(/-/g) || []).length > 2) {
                showAlert('El nombre no puede tener más de 2 guiones en total');
                return;
            }
            
            // 3. Validación estricta de caracteres especiales
            // Solo permitir letras, números, espacios, guiones y puntos
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ0-9\s\-\.]+$/.test(value)) {
                showAlert('El nombre solo puede contener letras, números, espacios, guiones (-) y puntos (.)');
                return;
            }
            
            // 4. No más de 3 caracteres repetidos seguidos
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El nombre no puede tener más de 3 caracteres repetidos seguidos');
                return;
            }
            
            // Validaciones adicionales
            if (value.length > 100) {
                showAlert('El nombre no puede exceder 100 caracteres');
                return;
            }
            if (value.trim() === '' && value.length > 0) {
                showAlert('El nombre no puede ser solo espacios en blanco');
                return;
            }
            if (/^\d/.test(value)) {
                showAlert('El nombre no puede comenzar con números');
                return;
            }
            if (/^\s/.test(value)) {
                showAlert('El nombre no puede comenzar con espacios');
                return;
            }
            if (/\s{2,}/.test(value)) {
                showAlert('El nombre no puede tener más de 1 espacio juntos');
                return;
            }
            if ((value.match(/\s/g) || []).length > 10) {
                showAlert('El nombre no puede tener más de 10 espacios en total');
                return;
            }
        }
        
        if (name === 'descripcion') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, descripcion: '' }));
                return;
            }
            
            // 1. No más de 4 números juntos (para permitir años)
            if (/\d{5,}/.test(value)) {
                showAlert('La descripción no puede tener más de 4 números juntos');
                return;
            }
            
            // 2. No más de 2 guiones juntos ni más de 2 guiones en total
            if (/-{3,}/.test(value)) {
                showAlert('La descripción no puede tener más de 2 guiones juntos');
                return;
            }
            if ((value.match(/-/g) || []).length > 2) {
                showAlert('La descripción no puede tener más de 2 guiones en total');
                return;
            }
            
            // 2.1. No más de 2 puntos juntos ni más de 2 puntos en total
            if (/\.{3,}/.test(value)) {
                showAlert('La descripción no puede tener más de 2 puntos juntos');
                return;
            }
            if ((value.match(/\./g) || []).length > 2) {
                showAlert('La descripción no puede tener más de 2 puntos en total');
                return;
            }
            
            // 3. Permitir caracteres especiales en descripción (más flexible)
            // Solo permitir letras, números, espacios, guiones, puntos y caracteres especiales comunes
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ0-9\s\-\.\,\;\:\!\?\"\'\(\)\[\]\{\}\/\+\=\*\&\^\%\$\#\@]+$/.test(value)) {
                showAlert('La descripción contiene caracteres no permitidos');
                return;
            }
            
            // 4. No más de 3 caracteres repetidos seguidos
            if (/(.)\1{2,}/.test(value)) {
                showAlert('La descripción no puede tener más de 3 caracteres repetidos seguidos');
                return;
            }
            
            // Validaciones adicionales
            if (value.length > 1000) {
                showAlert('La descripción no puede exceder 1000 caracteres');
                return;
            }
            if (value.trim() === '' && value.length > 0) {
                showAlert('La descripción no puede ser solo espacios en blanco');
                return;
            }
            if (/^\s/.test(value)) {
                showAlert('La descripción no puede comenzar con espacios');
                return;
            }
            if (/\s{2,}/.test(value)) {
                showAlert('La descripción no puede tener más de 1 espacio juntos');
                return;
            }
        }
        
        if (name === 'marca') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, marca: '' }));
                return;
            }
            
            // 1. Solo letras, números, espacios y guiones (no puntos para marca)
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ0-9\s\-]+$/.test(value)) {
                showAlert('La marca solo puede contener letras, números, espacios y guiones (-)');
                return;
            }
            
            // 1.1. No más de 4 números seguidos
            if (/\d{5,}/.test(value)) {
                showAlert('La marca no puede tener más de 4 números seguidos');
                return;
            }
            
            // 2. No más de 2 guiones juntos ni más de 1 guión en total
            if (/-{3,}/.test(value)) {
                showAlert('La marca no puede tener más de 2 guiones juntos');
                return;
            }
            if ((value.match(/-/g) || []).length > 1) {
                showAlert('La marca no puede tener más de 1 guión en total');
                return;
            }
            
            // 3. No más de 3 caracteres repetidos seguidos
            if (/(.)\1{2,}/.test(value)) {
                showAlert('La marca no puede tener más de 3 caracteres repetidos seguidos');
                return;
            }
            
            // Validaciones adicionales
            if (value.length > 50) {
                showAlert('La marca no puede exceder 50 caracteres');
                return;
            }
            if (value.trim() === '' && value.length > 0) {
                showAlert('La marca no puede ser solo espacios en blanco');
                return;
            }
            if (/^\d/.test(value)) {
                showAlert('La marca no puede comenzar con números');
                return;
            }
            if (/^\s/.test(value)) {
                showAlert('La marca no puede comenzar con espacios');
                return;
            }
            if (/\s{2,}/.test(value)) {
                showAlert('La marca no puede tener más de 1 espacio juntos');
                return;
            }
            if ((value.match(/\s/g) || []).length > 1) {
                showAlert('La marca no puede tener más de 1 espacio en total');
                return;
            }
        }
        
        if (name === 'codigoSKU') {
            // Si está vacío, permitir
            if (value === '') {
                setFormData(prev => ({ ...prev, codigoSKU: '' }));
                return;
            }
            
            // 1. Solo letras, números y guiones (sin espacios ni puntos para SKU)
            if (!/^[a-zA-Z0-9\-]+$/.test(value)) {
                showAlert('El código SKU solo puede contener letras, números y guiones (-), sin espacios');
                return;
            }
            
            // 2. No más de 2 guiones juntos ni más de 2 guiones en total
            if (/-{3,}/.test(value)) {
                showAlert('El código SKU no puede tener más de 2 guiones juntos');
                return;
            }
            if ((value.match(/-/g) || []).length > 2) {
                showAlert('El código SKU no puede tener más de 2 guiones en total');
                return;
            }
            
            // 3. No más de 3 caracteres repetidos seguidos
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El código SKU no puede tener más de 3 caracteres repetidos seguidos');
                return;
            }
            
            // 4. No puede comenzar con guión (permitir terminar con guión mientras se escribe)
            if (/^-/.test(value)) {
                showAlert('El código SKU no puede comenzar con guión');
                return;
            }
            
            // Validaciones adicionales
            if (value.length > 20) {
                showAlert('El código SKU no puede exceder 20 caracteres');
                return;
            }
        }
        
        setFormData(prev => ({
            ...prev,
            [name]: newValue
        }));

        if (errors[name]) {
            setErrors(prev => ({
                ...prev,
                [name]: null
            }));
        }
    };

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            const validTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp'];
            if (!validTypes.includes(file.type)) {
                showAlert('Solo se permiten imágenes JPG, PNG o WebP');
                e.target.value = '';
                setImagen(null);
                return;
            }
            
            if (file.size > 5 * 1024 * 1024) {
                showAlert('La imagen no puede exceder 5MB');
                e.target.value = '';
                setImagen(null);
                return;
            }
            
            const img = new Image();
            img.onload = function() {
                if (this.width < 200 || this.height < 200) {
                    showAlert('La imagen debe tener al menos 200x200 píxeles');
                    e.target.value = '';
                    setImagen(null);
                    return;
                }
                
                if (this.width > 4000 || this.height > 4000) {
                    showAlert('La imagen no puede exceder 4000x4000 píxeles');
                    e.target.value = '';
                    setImagen(null);
                    return;
                }
                
                setImagen(file);
                
                if (errors.imagen) {
                    setErrors(prev => ({ ...prev, imagen: null }));
                }
                
                const reader = new FileReader();
                reader.onload = (e) => setPreviewImagen(e.target.result);
                reader.readAsDataURL(file);
            };
            
            img.onerror = function() {
                showAlert('Archivo de imagen corrupto o no válido');
                e.target.value = '';
                setImagen(null);
            };
            
            img.src = URL.createObjectURL(file);
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        
        if (formData.descripcion.trim().length < 10) {
            showAlert('La descripción debe tener al menos 10 caracteres');
            return;
        }
        
        if (formData.codigoSKU.trim().length < 3) {
            showAlert('El código SKU debe tener al menos 3 caracteres');
            return;
        }
        
        if (formData.nombre.trim().length < 3) {
            showAlert('El nombre debe tener al menos 3 caracteres');
            return;
        }
        
        if (formData.marca.trim().length < 2) {
            showAlert('La marca debe tener al menos 2 caracteres');
            return;
        }
        
        const submitFormData = new FormData();
        
        Object.keys(formData).forEach(key => {
            if (key === 'precio') {
                const rawPrice = formData[key].replace(/\D/g, '');
                submitFormData.append(key, rawPrice);
            } else {
                submitFormData.append(key, formData[key]);
            }
        });
        
        if (imagen) {
            submitFormData.append('imagen', imagen);
        }

        handleEdit(producto.id, submitFormData);
    };

    const handleImageOnlyUpdate = () => {
        if (!imagen) {
            showAlert('Selecciona una nueva imagen primero');
            return;
        }

        const imageFormData = new FormData();
        imageFormData.append('imagen', imagen);

        handleEdit(producto.id, imageFormData, true);
    };

    const handleClose = () => {
        setShow(false);
        setFormData({
            nombre: '',
            descripcion: '',
            precio: '',
            categoria: '',
            stock: '',
            marca: '',
            codigoSKU: '',
            activo: true,
            oferta: false,
            descuento: 0
        });
        setImagen(null);
        setPreviewImagen(null);
        clearErrors();
    };

    if (!show) return null;

    return (
        <div className="crear-producto-overlay">
            <div className="crear-producto-modal">
                {alert && (
                    <div className="alert-notification">
                        <span>{alert}</span>
                    </div>
                )}
                
                <div className="crear-producto-header">
                    <h2>✏️ Editar Producto</h2>
                    <button 
                        className="close-button" 
                        onClick={handleClose}
                        type="button"
                    >
                        <FaTimes />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="crear-producto-form">
                    <div className="form-grid">
                        <div className="form-section">
                            <h3>📝 Información Básica</h3>
                            
                            <div className="form-group">
                                <label htmlFor="nombre">Nombre del Producto *</label>
                                <input
                                    type="text"
                                    id="nombre"
                                    name="nombre"
                                    value={formData.nombre}
                                    onChange={handleInputChange}
                                    placeholder="Ej: Lentes Ray-Ban Aviator Clásicos"
                                    className={errors.nombre ? 'error' : ''}
                                    maxLength={100}
                                />
                                {errors.nombre && <span className="error-message">{errors.nombre}</span>}
                            </div>

                            <div className="form-group">
                                <label htmlFor="descripcion">Descripción *</label>
                                <textarea
                                    id="descripcion"
                                    name="descripcion"
                                    value={formData.descripcion}
                                    onChange={handleInputChange}
                                    placeholder="Descripción detallada del producto, características, materiales, etc."
                                    className={errors.descripcion ? 'error' : ''}
                                    rows={4}
                                    maxLength={1000}
                                />
                                <small className="char-counter">{formData.descripcion.length}/1000</small>
                                {errors.descripcion && <span className="error-message">{errors.descripcion}</span>}
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="marca">Marca *</label>
                                    <input
                                        type="text"
                                        id="marca"
                                        name="marca"
                                        value={formData.marca}
                                        onChange={handleInputChange}
                                        placeholder="Ej: Ray-Ban"
                                        className={errors.marca ? 'error' : ''}
                                    />
                                    {errors.marca && <span className="error-message">{errors.marca}</span>}
                                </div>

                                <div className="form-group">
                                    <label htmlFor="codigoSKU">Código SKU *</label>
                                    <input
                                        type="text"
                                        id="codigoSKU"
                                        name="codigoSKU"
                                        value={formData.codigoSKU}
                                        onChange={handleInputChange}
                                        placeholder="Ej: RB-3025-001"
                                        className={errors.codigoSKU ? 'error' : ''}
                                    />
                                    {errors.codigoSKU && <span className="error-message">{errors.codigoSKU}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>🏷️ Precio y Categoría</h3>
                            
                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="precio">Precio (CLP) *</label>
                                    <input
                                        type="text"
                                        id="precio"
                                        name="precio"
                                        value={formData.precio}
                                        onChange={handlePriceChange}
                                        placeholder="149.990"
                                        className={errors.precio ? 'error' : ''}
                                    />
                                    {formData.precio && (
                                        <small className="precio-formateado">
                                            Precio: ${formData.precio} CLP
                                        </small>
                                    )}
                                    {errors.precio && <span className="error-message">{errors.precio}</span>}
                                </div>

                                <div className="form-group">
                                    <label>Categoría y Subcategoría *</label>
                                    <DropdownCategorias
                                        selectedCategoria={formData.categoria}
                                        selectedSubcategoria={formData.subcategoria}
                                        onCategoriaChange={(categoria) => setFormData(prev => ({ ...prev, categoria, subcategoria: '' }))}
                                        onSubcategoriaChange={(subcategoria) => setFormData(prev => ({ ...prev, subcategoria }))}
                                        className={errors.categoria || errors.subcategoria ? 'error' : ''}
                                        dropdownActivo={dropdownActivo}
                                        setDropdownActivo={setDropdownActivo}
                                        id="editar-producto"
                                    />
                                    {errors.categoria && <span className="error-message">{errors.categoria}</span>}
                                    {errors.subcategoria && <span className="error-message">{errors.subcategoria}</span>}
                                </div>
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="stock">Stock *</label>
                                    <input
                                        type="number"
                                        id="stock"
                                        name="stock"
                                        value={formData.stock}
                                        onChange={handleInputChange}
                                        onKeyPress={(e) => {
                                            if (!/[0-9]/.test(e.key)) {
                                                e.preventDefault();
                                            }
                                        }}
                                        onInput={(e) => {
                                            // Validación adicional para prevenir pegar texto
                                            const value = e.target.value;
                                            if (!/^\d*$/.test(value)) {
                                                e.target.value = value.replace(/\D/g, '');
                                                showAlert('El stock solo puede contener números');
                                            }
                                        }}
                                        placeholder="50"
                                        min="0"
                                        max="99999"
                                        inputMode="numeric"
                                        className={errors.stock ? 'error' : ''}
                                    />
                                    {errors.stock && <span className="error-message">{errors.stock}</span>}
                                </div>

                                <div className="form-group">
                                    <label htmlFor="descuento">Descuento (%)</label>
                                    <input
                                        type="number"
                                        id="descuento"
                                        name="descuento"
                                        value={formData.descuento}
                                        onChange={handleInputChange}
                                        onKeyPress={(e) => {
                                            if (!/[0-9]/.test(e.key)) {
                                                e.preventDefault();
                                            }
                                        }}
                                        onInput={(e) => {
                                            // Validación adicional para prevenir pegar texto
                                            const value = e.target.value;
                                            if (!/^\d*$/.test(value)) {
                                                e.target.value = value.replace(/\D/g, '');
                                                showAlert('El descuento solo puede contener números');
                                            }
                                        }}
                                        placeholder="0"
                                        min="0"
                                        max="100"
                                        inputMode="numeric"
                                        className={errors.descuento ? 'error' : ''}
                                    />
                                    {errors.descuento && <span className="error-message">{errors.descuento}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>📷 Imagen del Producto</h3>
                            
                            <div className="image-upload-section">
                                <div 
                                    className={`image-upload-area ${errors.imagen ? 'error' : ''}`}
                                    onClick={() => fileInputRef.current?.click()}
                                >
                                    {previewImagen ? (
                                        <div className="image-preview">
                                            <img src={previewImagen} alt="Preview" />
                                            <div className="image-overlay">
                                                <FaImage size={24} />
                                                <span>Cambiar imagen</span>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="upload-placeholder">
                                            <FaUpload size={48} />
                                            <h4>Subir nueva imagen</h4>
                                            <p>JPG, PNG o WebP • Máximo 5MB</p>
                                            <p>Recomendado: 800x600px</p>
                                        </div>
                                    )}
                                </div>
                                
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    accept="image/jpeg,image/jpg,image/png,image/webp"
                                    onChange={handleImageChange}
                                    style={{ display: 'none' }}
                                />
                                
                                {errors.imagen && <span className="error-message">{errors.imagen}</span>}
                                
                                {imagen && (
                                    <button
                                        type="button"
                                        onClick={handleImageOnlyUpdate}
                                        className="btn-create"
                                        disabled={loading}
                                        style={{ marginTop: '10px', width: '100%' }}
                                    >
                                        {loading ? (
                                            <>
                                                <FaSpinner className="spinner" />
                                                Actualizando imagen...
                                            </>
                                        ) : (
                                            'Actualizar solo imagen'
                                        )}
                                    </button>
                                )}
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>⚙️ Configuración</h3>
                            
                            <div className="checkbox-group">
                                <label className="checkbox-label">
                                    <input
                                        type="checkbox"
                                        name="activo"
                                        checked={formData.activo}
                                        onChange={handleInputChange}
                                    />
                                    <span className="checkbox-custom"></span>
                                    Producto activo (visible en la tienda)
                                </label>

                                <label className="checkbox-label">
                                    <input
                                        type="checkbox"
                                        name="oferta"
                                        checked={formData.oferta}
                                        onChange={handleInputChange}
                                    />
                                    <span className="checkbox-custom"></span>
                                    Producto en oferta
                                </label>
                            </div>
                        </div>
                    </div>

                    <div className="form-actions">
                        <button
                            type="button"
                            onClick={handleClose}
                            className="btn-cancel"
                            disabled={loading}
                        >
                            Cancelar
                        </button>
                        <button
                            type="submit"
                            className="btn-create"
                            disabled={loading || !isFormValid()}
                        >
                            {loading ? (
                                <>
                                    <FaSpinner className="spinner" />
                                    Actualizando producto...
                                </>
                            ) : (
                                'Actualizar Producto'
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default EditarProductoPopup;

import { useState, useEffect } from 'react';
import { FaTimes, FaUser, FaEnvelope, FaIdCard, FaPhone, FaCalendar, FaLock, FaEye, FaEyeSlash, FaSpinner } from 'react-icons/fa';
import useEditUser from '@hooks/users/useEditUser';
import { validationRules } from '@helpers/validation.helper';
import { formatRut, formatTelefono } from '@helpers/formatData';
import { getNombreCompleto } from '@helpers/nameHelpers';
import DatePicker from './DatePicker';
import '@styles/crearUsuario.css';

const EditarUsuarioPopup = ({ show, setShow, usuario, onUsuarioUpdated }) => {
    const { handleEditUser, loading } = useEditUser();
    
    const [formData, setFormData] = useState({
        primerNombre: '',
        segundoNombre: '',
        apellidoPaterno: '',
        apellidoMaterno: '',
        rut: '',
        email: '',
        password: '',
        newPassword: '',
        confirmNewPassword: '',
        telefono: '',
        fechaNacimiento: '',
        genero: '',
        rol: 'usuario'
    });

    const [errors, setErrors] = useState({});
    const [showPassword, setShowPassword] = useState(false);
    const [showNewPassword, setShowNewPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    const [changePassword, setChangePassword] = useState(false);
    const [rutModified, setRutModified] = useState(false);
    const [alert, setAlert] = useState(null);

    useEffect(() => {
        if (show) {
            document.body.classList.add('no-scroll');
        } else {
            document.body.classList.remove('no-scroll');
        }

        return () => {
            document.body.classList.remove('no-scroll');
        };
    }, [show]);

    const showAlert = (message) => {
        setAlert(message);
        setTimeout(() => setAlert(null), 2000);
    };

    // Cargar datos del usuario cuando se abre el modal
    useEffect(() => {
        if (show && usuario) {
            setFormData({
                primerNombre: usuario.primerNombre || '',
                segundoNombre: usuario.segundoNombre || '',
                apellidoPaterno: usuario.apellidoPaterno || '',
                apellidoMaterno: usuario.apellidoMaterno || '',
                rut: usuario.rut || '',
                email: usuario.email || '',
                password: '',
                newPassword: '',
                confirmNewPassword: '',
                telefono: usuario.telefono || '',
                fechaNacimiento: usuario.fechaNacimiento ? usuario.fechaNacimiento.split('T')[0] : '',
                genero: usuario.genero || '',
                rol: usuario.rol || 'usuario'
            });
            setChangePassword(false);
            setErrors({});
            setRutModified(false);
            setAlert(null);
        }
    }, [show, usuario]);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        let newValue = value;
        
        // Validaciones específicas durante la escritura
        if (name === 'rut') {
            // Solo permitir números y K
            if (!/^[0-9kK\.\-]*$/.test(value)) {
                showAlert('El RUT solo puede contener números y la letra K');
                return;
            }
            newValue = formatRut(value);
            setRutModified(true);
        } else if (name === 'telefono') {
            // Solo permitir números y el símbolo +
            if (!/^[\+\d\s]*$/.test(value)) {
                showAlert('El teléfono solo puede contener números y el símbolo +');
                return;
            }
            newValue = value.replace(/[^\+\d]/g, '');
        } else if (['primerNombre', 'apellidoPaterno'].includes(name)) {
            // Validaciones para nombres sin espacios
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ]*$/.test(value)) {
                showAlert('Los nombres solo pueden contener letras (sin espacios)');
                return;
            }
            
            // No permitir espacios
            if (/\s/.test(value)) {
                showAlert('El nombre no puede contener espacios');
                return;
            }
            
            // No permitir completamente en mayúsculas
            if (value === value.toUpperCase() && value.length > 1) {
                showAlert('El nombre no puede estar completamente en mayúsculas');
                return;
            }
            
            // Validar mayúsculas correctas (solo si tiene más de 1 carácter)
            if (value.length > 1) {
                // La primera letra debe ser mayúscula
                if (value[0] !== value[0].toUpperCase()) {
                    showAlert('El nombre debe tener mayúscula al inicio');
                    return;
                }
                // El resto debe ser minúscula
                if (value.slice(1) !== value.slice(1).toLowerCase()) {
                    showAlert('El nombre solo debe tener mayúscula al inicio');
                    return;
                }
            }
            
            // No más de 2 letras iguales consecutivas
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El nombre no puede tener más de 2 letras iguales consecutivas');
                return;
            }
            
            // Limitar longitud
            if (value.length > 50) {
                showAlert('El nombre no puede exceder 50 caracteres');
                return;
            }
        } else if (name === 'segundoNombre') {
            // Validaciones para segundo nombre (puede tener 1 espacio)
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ\s]*$/.test(value)) {
                showAlert('El segundo nombre solo puede contener letras y espacios');
                return;
            }
            
            // No permitir más de 1 espacio consecutivo
            if (/\s{2,}/.test(value)) {
                showAlert('No se permiten más de 1 espacio consecutivo');
                return;
            }
            
            // No permitir empezar con espacio
            if (/^\s/.test(value) && value.length === 1) {
                showAlert('El segundo nombre no puede empezar con un espacio');
                return;
            }
            
            // No permitir completamente en mayúsculas
            if (value === value.toUpperCase() && value.length > 1) {
                showAlert('El segundo nombre no puede estar completamente en mayúsculas');
                return;
            }
            
            // Validar mayúsculas correctas (solo si tiene más de 1 carácter)
            if (value.length > 1) {
                const words = value.split(' ');
                for (let i = 0; i < words.length; i++) {
                    const word = words[i];
                    if (word.length > 0) {
                        // La primera letra debe ser mayúscula
                        if (word[0] !== word[0].toUpperCase()) {
                            showAlert('El segundo nombre debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                        // El resto debe ser minúscula
                        if (word.length > 1 && word.slice(1) !== word.slice(1).toLowerCase()) {
                            showAlert('El segundo nombre solo debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                    }
                }
            }
            
            // No más de 2 letras iguales consecutivas
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El segundo nombre no puede tener más de 2 letras iguales consecutivas');
                return;
            }
            
            // Limitar longitud
            if (value.length > 50) {
                showAlert('El segundo nombre no puede exceder 50 caracteres');
                return;
            }
        } else if (name === 'apellidoMaterno') {
            // Validaciones para apellido materno (hasta 2 espacios)
            if (!/^[a-zA-ZáéíóúÁÉÍÓÚñÑ\s]*$/.test(value)) {
                showAlert('El apellido materno solo puede contener letras y espacios');
                return;
            }
            
            // No permitir más de 1 espacio consecutivo
            if (/\s{2,}/.test(value)) {
                showAlert('No se permiten más de 1 espacio consecutivo');
                return;
            }
            
            // No permitir empezar con espacio
            if (/^\s/.test(value) && value.length === 1) {
                showAlert('El apellido materno no puede empezar con un espacio');
                return;
            }
            
            // No permitir completamente en mayúsculas
            if (value === value.toUpperCase() && value.length > 1) {
                showAlert('El apellido materno no puede estar completamente en mayúsculas');
                return;
            }
            
            // Validar mayúsculas correctas (solo si tiene más de 1 carácter)
            if (value.length > 1) {
                const words = value.split(' ');
                for (let i = 0; i < words.length; i++) {
                    const word = words[i];
                    if (word.length > 0) {
                        // La primera letra debe ser mayúscula
                        if (word[0] !== word[0].toUpperCase()) {
                            showAlert('El apellido materno debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                        // El resto debe ser minúscula
                        if (word.length > 1 && word.slice(1) !== word.slice(1).toLowerCase()) {
                            showAlert('El apellido materno solo debe tener mayúscula al inicio de cada palabra');
                            return;
                        }
                    }
                }
            }
            
            // No más de 2 letras iguales consecutivas
            if (/(.)\1{2,}/.test(value)) {
                showAlert('El apellido materno no puede tener más de 2 letras iguales consecutivas');
                return;
            }
            
            // Limitar longitud
            if (value.length > 50) {
                showAlert('El apellido materno no puede exceder 50 caracteres');
                return;
            }
        } else if (name === 'email') {
            // Básicamente no validar durante escritura, solo al enviar
            newValue = value.toLowerCase();
        }
        
        setFormData(prev => ({ ...prev, [name]: newValue }));
        
        // Limpiar error al escribir
        if (errors[name]) {
            setErrors(prev => ({ ...prev, [name]: '' }));
        }
    };

    const isFormValid = () => {
        return (
            formData.primerNombre.trim().length >= 2 &&
            formData.apellidoPaterno.trim().length >= 2 &&
            formData.rut.trim().length >= 11 &&
            formData.email.trim().length >= 5 &&
            (!changePassword || (
                formData.password.length >= 6 &&
                formData.newPassword.length >= 6 &&
                formData.confirmNewPassword.length >= 6 &&
                formData.newPassword === formData.confirmNewPassword
            ))
        );
    };

    const validateForm = () => {
        const newErrors = {};

        // Validar primer nombre
        const primerNombreError = validationRules.nombre(formData.primerNombre, 'Primer nombre');
        if (primerNombreError || !formData.primerNombre.trim()) {
            newErrors.primerNombre = primerNombreError || 'El primer nombre es requerido';
        }

        // Validar segundo nombre (opcional)
        if (formData.segundoNombre.trim()) {
            const segundoNombreError = validationRules.segundoNombre(formData.segundoNombre, 'Segundo nombre');
            if (segundoNombreError) {
                newErrors.segundoNombre = segundoNombreError;
            }
        }

        // Validar apellido paterno
        const apellidoPaternoError = validationRules.apellidoPaterno(formData.apellidoPaterno, 'Apellido paterno');
        if (apellidoPaternoError || !formData.apellidoPaterno.trim()) {
            newErrors.apellidoPaterno = apellidoPaternoError || 'El apellido paterno es requerido';
        }

        // Validar apellido materno (opcional)
        if (formData.apellidoMaterno.trim()) {
            const apellidoMaternoError = validationRules.apellidoMaterno(formData.apellidoMaterno, 'Apellido materno');
            if (apellidoMaternoError) {
                newErrors.apellidoMaterno = apellidoMaternoError;
            }
        }

        // Validar RUT solo si ha sido modificado
        if (rutModified) {
            const rutError = validationRules.rut(formData.rut);
            if (rutError) {
                newErrors.rut = rutError;
            }
        } else if (!formData.rut.trim()) {
            newErrors.rut = 'El RUT es requerido';
        }

        // Validar email
        const emailError = validationRules.email(formData.email);
        if (emailError || !formData.email.trim()) {
            newErrors.email = emailError || 'El email es requerido';
        }

        // Validar contraseña solo si se quiere cambiar
        if (changePassword) {
            if (!formData.password.trim()) {
                newErrors.password = 'La contraseña actual es requerida';
            }

            if (!formData.newPassword.trim()) {
                newErrors.newPassword = 'La nueva contraseña es requerida';
            } else {
                const newPasswordError = validationRules.newPassword(formData.newPassword);
                if (newPasswordError) {
                    newErrors.newPassword = newPasswordError;
                }
            }

            if (!formData.confirmNewPassword.trim()) {
                newErrors.confirmNewPassword = 'Confirmar nueva contraseña es requerido';
            } else if (formData.newPassword !== formData.confirmNewPassword) {
                newErrors.confirmNewPassword = 'Las contraseñas no coinciden';
            }
        }

        // Validar teléfono (opcional)
        if (formData.telefono.trim()) {
            const telefonoError = validationRules.telefonoChileno(formData.telefono);
            if (telefonoError) {
                newErrors.telefono = telefonoError;
            }
        }

        // Validar fecha de nacimiento (opcional)
        if (formData.fechaNacimiento) {
            const fechaError = validationRules.fechaNacimiento(formData.fechaNacimiento);
            if (fechaError) {
                newErrors.fechaNacimiento = fechaError;
            }
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const resetForm = () => {
        setFormData({
            primerNombre: '',
            segundoNombre: '',
            apellidoPaterno: '',
            apellidoMaterno: '',
            rut: '',
            email: '',
            password: '',
            newPassword: '',
            confirmNewPassword: '',
            telefono: '',
            fechaNacimiento: '',
            genero: '',
            rol: 'usuario'
        });
        setErrors({});
        setChangePassword(false);
        setRutModified(false);
        setAlert(null);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (!validateForm()) {
            showAlert('Por favor, corrige los errores en el formulario');
            return;
        }

        const userData = {
            primerNombre: formData.primerNombre.trim(),
            segundoNombre: formData.segundoNombre.trim() || null,
            apellidoPaterno: formData.apellidoPaterno.trim(),
            apellidoMaterno: formData.apellidoMaterno.trim() || null,
            rut: formData.rut.trim(),
            email: formData.email.trim().toLowerCase(),
            telefono: formData.telefono.trim() || null,
            fechaNacimiento: formData.fechaNacimiento || null,
            genero: formData.genero || null,
            rol: formData.rol
        };

        // Agregar campos de contraseña solo si se quiere cambiar
        if (changePassword) {
            userData.password = formData.password;
            userData.newPassword = formData.newPassword;
        }

        const query = { id: usuario.id };
        const result = await handleEditUser(userData, query);
        
        if (result.success) {
            onUsuarioUpdated();
            handleClose();
        } else if (result.field) {
            setErrors(prev => ({ ...prev, [result.field]: result.error }));
        } else {
            showAlert(result.error || 'Error al actualizar el usuario');
        }
    };

    const handleClose = () => {
        setShow(false);
        resetForm();
    };

    if (!show || !usuario) return null;

    return (
        <div className="crear-usuario-overlay">
            <div className="crear-usuario-modal">
                {alert && (
                    <div className="alert-notification">
                        <span>{alert}</span>
                    </div>
                )}
                
                <div className="crear-usuario-header">
                    <h2>✏️ Editar Usuario: {getNombreCompleto(usuario)}</h2>
                    <button 
                        className="close-button" 
                        onClick={handleClose}
                        type="button"
                        disabled={loading}
                    >
                        <FaTimes />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="crear-usuario-form">
                    <div className="usuario-form-grid">
                        <div className="form-section">
                            <h3>📝 Información Personal</h3>
                            
                        <div className="form-row">
                            <div className="form-group">
                                    <label htmlFor="primerNombre">Primer Nombre *</label>
                                <input
                                    type="text"
                                    id="primerNombre"
                                    name="primerNombre"
                                    value={formData.primerNombre}
                                    onChange={handleInputChange}
                                    className={errors.primerNombre ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: Juan"
                                        maxLength={50}
                                />
                                {errors.primerNombre && <span className="error-message">{errors.primerNombre}</span>}
                            </div>

                            <div className="form-group">
                                    <label htmlFor="segundoNombre">Segundo Nombre</label>
                                <input
                                    type="text"
                                    id="segundoNombre"
                                    name="segundoNombre"
                                    value={formData.segundoNombre}
                                    onChange={handleInputChange}
                                        className={errors.segundoNombre ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: Carlos (opcional)"
                                        maxLength={50}
                                />
                                    {errors.segundoNombre && <span className="error-message">{errors.segundoNombre}</span>}
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                    <label htmlFor="apellidoPaterno">Apellido Paterno *</label>
                                <input
                                    type="text"
                                    id="apellidoPaterno"
                                    name="apellidoPaterno"
                                    value={formData.apellidoPaterno}
                                    onChange={handleInputChange}
                                    className={errors.apellidoPaterno ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: Pérez"
                                        maxLength={50}
                                />
                                {errors.apellidoPaterno && <span className="error-message">{errors.apellidoPaterno}</span>}
                            </div>

                            <div className="form-group">
                                    <label htmlFor="apellidoMaterno">Apellido Materno</label>
                                <input
                                    type="text"
                                    id="apellidoMaterno"
                                    name="apellidoMaterno"
                                    value={formData.apellidoMaterno}
                                    onChange={handleInputChange}
                                        className={errors.apellidoMaterno ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="Ej: González (opcional)"
                                        maxLength={50}
                                />
                                    {errors.apellidoMaterno && <span className="error-message">{errors.apellidoMaterno}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>🆔 Identificación y Contacto</h3>

                        <div className="form-row">
                            <div className="form-group">
                                <label htmlFor="rut">
                                    <FaIdCard className="label-icon" />
                                    RUT *
                                </label>
                                <input
                                    type="text"
                                    id="rut"
                                    name="rut"
                                    value={formData.rut}
                                    onChange={handleInputChange}
                                    className={errors.rut ? 'error' : ''}
                                    disabled={loading}
                                    placeholder="12.345.678-9"
                                        maxLength={12}
                                />
                                    {rutModified && formData.rut && (
                                        <small className="rut-formatted">
                                            RUT: {formData.rut}
                                        </small>
                                    )}
                                {errors.rut && <span className="error-message">{errors.rut}</span>}
                            </div>

                            <div className="form-group">
                                <label htmlFor="email">
                                    <FaEnvelope className="label-icon" />
                                    Email *
                                </label>
                                <input
                                    type="email"
                                    id="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleInputChange}
                                    className={errors.email ? 'error' : ''}
                                    disabled={loading}
                                    placeholder="usuario@ejemplo.com"
                                        maxLength={100}
                                />
                                {errors.email && <span className="error-message">{errors.email}</span>}
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label htmlFor="telefono">
                                    <FaPhone className="label-icon" />
                                    Teléfono
                                </label>
                                <input
                                    type="tel"
                                    id="telefono"
                                    name="telefono"
                                    value={formData.telefono}
                                    onChange={handleInputChange}
                                    className={errors.telefono ? 'error' : ''}
                                    disabled={loading}
                                        placeholder="+56912345678"
                                        maxLength={15}
                                />
                                    {formData.telefono && (
                                        <small className="telefono-formatted">
                                            Teléfono: {formatTelefono(formData.telefono)}
                                        </small>
                                    )}
                                {errors.telefono && <span className="error-message">{errors.telefono}</span>}
                            </div>

                            <div className="form-group">
                                <label htmlFor="fechaNacimiento">
                                    <FaCalendar className="label-icon" />
                                    Fecha de Nacimiento
                                </label>
                                    <DatePicker
                                    value={formData.fechaNacimiento}
                                        onChange={(value) => {
                                            setFormData(prev => ({ ...prev, fechaNacimiento: value }));
                                            if (errors.fechaNacimiento) {
                                                setErrors(prev => ({ ...prev, fechaNacimiento: '' }));
                                            }
                                        }}
                                        placeholder="Seleccionar fecha"
                                    disabled={loading}
                                />
                                {errors.fechaNacimiento && <span className="error-message">{errors.fechaNacimiento}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="form-section">
                            <h3>⚙️ Configuración</h3>

                        <div className="form-row">
                            <div className="form-group">
                                    <label htmlFor="genero">Género</label>
                                <select
                                    id="genero"
                                    name="genero"
                                    value={formData.genero}
                                    onChange={handleInputChange}
                                    disabled={loading}
                                >
                                    <option value="">Seleccionar género</option>
                                    <option value="masculino">Masculino</option>
                                    <option value="femenino">Femenino</option>
                                    <option value="otro">Otro</option>
                                    <option value="no especificar">Prefiero no especificar</option>
                                </select>
                            </div>

                            <div className="form-group">
