import { useForm } from 'react-hook-form';
import { useState } from 'react';
import '@styles/form.css';
import HideIcon from '@assets/HideIcon.svg';
import ViewIcon from '@assets/ViewIcon.svg';

const Form = ({ title, fields, buttonText, onSubmit, footerContent, backgroundColor }) => {
    const { register, handleSubmit, formState: { errors }, setValue, watch } = useForm();
    const [showPassword, setShowPassword] = useState(false);
    const [showNewPassword, setShowNewPassword] = useState(false);

    const togglePasswordVisibility = () => {
        setShowPassword(!showPassword);
    };

    const toggleNewPasswordVisibility = () => {
        setShowNewPassword(!showNewPassword);
    };

    const onFormSubmit = (data) => {
        onSubmit(data);
    };

    // Función para manejar cambios en campos numéricos
    const handleNumericChange = (e, fieldName) => {
        const value = e.target.value;
        // Solo permitir números
        const cleanValue = value.replace(/[^0-9]/g, '');
        
        if (value !== cleanValue) {
            e.target.value = cleanValue;
            setValue(fieldName, cleanValue);
        }
    };

    return (
        <form
            className="form"
            style={{ backgroundColor: backgroundColor }}
            onSubmit={handleSubmit(onFormSubmit)}
            autoComplete="off"
        >
            <h1>{title}</h1>
            {fields.map((field, index) => (
                <div className="container_inputs" key={index}>
                    {field.label && <label htmlFor={field.name}>{field.label}</label>}
                    {field.fieldType === 'input' && (
                        <input
                            {...register(field.name, {
                                required: field.required ? 'Este campo es obligatorio' : false,
                                minLength: field.minLength ? { value: field.minLength, message: `Debe tener al menos ${field.minLength} caracteres` } : false,
                                maxLength: field.maxLength ? { value: field.maxLength, message: `Debe tener máximo ${field.maxLength} caracteres` } : false,
                                pattern: field.pattern ? { value: field.pattern, message: field.patternMessage || 'Formato no válido' } : false,
                                validate: field.validate || {},
                            })}
                            name={field.name}
                            placeholder={field.placeholder}
                            type={field.type === 'password' && field.name === 'password' ? (showPassword ? 'text' : 'password') :
                                field.type === 'password' && field.name === 'newPassword' ? (showNewPassword ? 'text' : 'password') :
                                    field.type}
                            defaultValue={field.defaultValue || ''}
                            disabled={field.disabled}
                            onChange={(e) => {
                                // Para campos numéricos, usar la función personalizada
                                if (field.type === 'text' && field.pattern && field.pattern.toString().includes('[0-9]')) {
                                    handleNumericChange(e, field.name);
                                }
                                if (field.onChange) {
                                    field.onChange(e);
                                }
                            }}
                            min={field.min}
                            max={field.max}
                            onKeyPress={(e) => {
                                // Para campos numéricos (tanto type="number" como type="text" con patrón numérico)
                                if (field.type === 'number' || (field.type === 'text' && field.pattern && field.pattern.toString().includes('[0-9]'))) {
                                    // Solo permitir números del 0-9
                                    if (!/[0-9]/.test(e.key)) {
                                        e.preventDefault();
                                    }
                                }
                            }}
                            onInput={(e) => {
                                // Para campos numéricos (tanto type="number" como type="text" con patrón numérico)
                                if (field.type === 'number' || (field.type === 'text' && field.pattern && field.pattern.toString().includes('[0-9]'))) {
                                    const value = e.target.value;
                                    // Eliminar cualquier carácter que no sea número
                                    let cleanValue = value.replace(/[^0-9]/g, '');
                                    
                                    // Verificar límites si están definidos
                                    if (field.max && cleanValue) {
                                        const numValue = parseInt(cleanValue);
                                        if (numValue > field.max) {
                                            cleanValue = field.max.toString();
                                        }
                                    }
                                    
                                    if (value !== cleanValue) {
                                        e.target.value = cleanValue;
                                        setValue(field.name, cleanValue);
                                        // Forzar la actualización del formulario
                                        e.target.dispatchEvent(new Event('input', { bubbles: true }));
                                        // También disparar el evento change para react-hook-form
                                        e.target.dispatchEvent(new Event('change', { bubbles: true }));
                                    }
                                }
                            }}
                            onPaste={(e) => {
                                // Para campos numéricos (tanto type="number" como type="text" con patrón numérico)
                                if (field.type === 'number' || (field.type === 'text' && field.pattern && field.pattern.toString().includes('[0-9]'))) {
                                    e.preventDefault();
                                    const pastedText = (e.clipboardData || window.clipboardData).getData('text');
                                    // Solo permitir números
                                    const numbersOnly = pastedText.replace(/[^0-9]/g, '');
                                    e.target.value = numbersOnly;
                                    setValue(field.name, numbersOnly);
                                    // Forzar la actualización del formulario
                                    e.target.dispatchEvent(new Event('input', { bubbles: true }));
                                    // También disparar el evento change para react-hook-form
                                    e.target.dispatchEvent(new Event('change', { bubbles: true }));
                                }
                            }}
                            onDrop={(e) => {
                                // Para campos numéricos (tanto type="number" como type="text" con patrón numérico)
                                if (field.type === 'number' || (field.type === 'text' && field.pattern && field.pattern.toString().includes('[0-9]'))) {
                                    e.preventDefault();
                                }
                            }}
                        />
                    )}
                    {field.fieldType === 'textarea' && (
                        <textarea
                            {...register(field.name, {
                                required: field.required ? 'Este campo es obligatorio' : false,
                                minLength: field.minLength ? { value: field.minLength, message: `Debe tener al menos ${field.minLength} caracteres` } : false,
                                maxLength: field.maxLength ? { value: field.maxLength, message: `Debe tener máximo ${field.maxLength} caracteres` } : false,
                                pattern: field.pattern ? { value: field.pattern, message: field.patternMessage || 'Formato no válido' } : false,
                                validate: field.validate || {},
                            })}
                            name={field.name}
                            placeholder={field.placeholder}
                            defaultValue={field.defaultValue || ''}
                            disabled={field.disabled}
                            onChange={field.onChange}
                        />
                    )}
                    {field.fieldType === 'select' && (
                        <select
                            {...register(field.name, {
                                required: field.required ? 'Este campo es obligatorio' : false,
                                validate: field.validate || {},
                            })}
                            name={field.name}
                            defaultValue={field.defaultValue || ''}
                            disabled={field.disabled}
                            onChange={field.onChange}
                        >
                            <option value="">Seleccionar opción</option>
                            {field.options && field.options.map((option, optIndex) => (
                                <option className="options-class" key={optIndex} value={option.value}>
                                    {option.label}
                                </option>
                            ))}
                        </select>
                    )}
                    {field.type === 'password' && field.name === 'password' && (
                        <span className="toggle-password-icon" onClick={togglePasswordVisibility}>
                            <img src={showPassword ? ViewIcon : HideIcon} />
                        </span>
                    )}
                    {field.type === 'password' && field.name === 'newPassword' && (
                        <span className="toggle-password-icon" onClick={toggleNewPasswordVisibility}>
                            <img src={showNewPassword ? ViewIcon : HideIcon} />
                        </span>
                    )}
                    <div className={`error-message ${errors[field.name] || field.errorMessageData ? 'visible' : ''}`}>
                        {errors[field.name]?.message || field.errorMessageData || ''}
                    </div>
                </div>
            ))}
            {buttonText && <button type="submit">{buttonText}</button>}
            {footerContent && <div className="footerContent">{footerContent}</div>}
        </form>
    );
};

export default Form;

import { createContext, useEffect, useState, useCallback } from 'react';
import { getProfile, updateProfile } from '@services/auth.service.js';
import { decodeToken, clearTokenCache } from '@helpers/jwt.helper';

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [userChangeFlag, setUserChangeFlag] = useState(0);

    const isTokenValid = async (token) => {
        if (!token) return false;

        try {
            const decodedToken = await decodeToken(token);
            if (!decodedToken) return false;

            const currentTime = Date.now() / 1000;
            return decodedToken.exp > currentTime;
        } catch {
            return false;
        }
    };

    const fetchUser = useCallback(async () => {
        try {
            const storedUser = localStorage.getItem('user');
            const token = localStorage.getItem('token');
            
            if (storedUser && token) {
                const tokenIsValid = await isTokenValid(token);
                
                if (tokenIsValid) {
                    setUser(JSON.parse(storedUser));
                    setLoading(false);
                    return;
                } else {
                    localStorage.removeItem('token');
                    localStorage.removeItem('user');
                }
            }
            
            if (token && await isTokenValid(token)) {
                const data = await getProfile();
                if (data) {
                    setUser(data);
                    localStorage.setItem('user', JSON.stringify(data));
                }
            } else {
                setUser(null);
            }
        } catch (error) {
            console.error('Error en fetchUser:', error);
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            setUser(null);
        } finally {
            setLoading(false);
        }
    }, []);

    const refreshUser = async () => {
        setLoading(true);
        await fetchUser();
        setUserChangeFlag(prev => prev + 1);
    };

    const updateUser = async (userData) => {
        try {
            const updatedUser = await updateProfile(userData);
            setUser(updatedUser);
            localStorage.setItem('user', JSON.stringify(updatedUser));
            setUserChangeFlag(prev => prev + 1);
            return updatedUser;
        } catch (error) {
            console.error('Error al actualizar usuario:', error);
            throw error;
        }
    };

    const logout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        clearTokenCache(); 
        setUser(null);
        setUserChangeFlag(prev => prev + 1);
        
        setTimeout(() => {
            window.dispatchEvent(new CustomEvent('userChanged'));
        }, 300);
        
        window.location.href = '/OpticaDanniels';
    };

    useEffect(() => {
        fetchUser();
    }, [fetchUser]);

    return (
        <AuthContext.Provider
            value={{
                user,
                setUser,
                loading,
                isAuthenticated: !!user,
                refreshUser,
                updateUser,
                logout,
                userChangeFlag,
            }}
        >
            {children}
        </AuthContext.Provider>
    );
};

import { createContext, useContext, useReducer, useEffect } from 'react';
import { useAuth } from '@hooks/useAuth';

const CartContext = createContext();

const CART_KEY_BASE = 'optica-danniels-cart';

// Tipos de acciones
const CART_ACTIONS = {
    LOAD_CART: 'LOAD_CART',
    ADD_ITEM: 'ADD_ITEM',
    REMOVE_ITEM: 'REMOVE_ITEM',
    UPDATE_QUANTITY: 'UPDATE_QUANTITY',
    CLEAR_CART: 'CLEAR_CART'
};

// Reducer del carrito - Patrón usado por sitios exitosos
const cartReducer = (state, action) => {
    switch (action.type) {
        case CART_ACTIONS.LOAD_CART:
            return {
                ...state,
                items: action.payload.items || [],
                version: state.version + 1
            };

        case CART_ACTIONS.ADD_ITEM: {
            const existingItem = state.items.find(item => item.id === action.payload.id);
            let newItems;
            
            if (existingItem) {
                newItems = state.items.map(item =>
                    item.id === action.payload.id
                        ? { ...item, cantidad: item.cantidad + (action.payload.cantidad || 1) }
                        : item
                );
            } else {
                newItems = [...state.items, { ...action.payload, cantidad: action.payload.cantidad || 1 }];
            }

            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify(newItems));
            
            return {
                ...state,
                items: newItems,
                version: state.version + 1
            };
        }

        case CART_ACTIONS.REMOVE_ITEM: {
            const newItems = state.items.filter(item => item.id !== action.payload.productId);
            
            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify(newItems));
            
            return {
                ...state,
                items: newItems,
                version: state.version + 1
            };
        }

        case CART_ACTIONS.UPDATE_QUANTITY: {
            let newItems;
            
            if (action.payload.cantidad <= 0) {
                newItems = state.items.filter(item => item.id !== action.payload.productId);
            } else {
                newItems = state.items.map(item =>
                    item.id === action.payload.productId
                        ? { ...item, cantidad: action.payload.cantidad }
                        : item
                );
            }

            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify(newItems));
            
            return {
                ...state,
                items: newItems,
                version: state.version + 1
            };
        }

        case CART_ACTIONS.CLEAR_CART: {
            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify([]));
            
            return {
                ...state,
                items: [],
                version: state.version + 1
            };
        }

        default:
            return state;
    }
};

// Provider del carrito
export const CartProvider = ({ children }) => {
    const { user, isAuthenticated } = useAuth();
    const [state, dispatch] = useReducer(cartReducer, {
        items: [],
        version: 0
    });

    // Función para obtener la clave del carrito
    const getCartKey = () => {
        const userRut = user?.rut;
        return userRut ? `${CART_KEY_BASE}-${userRut}` : `${CART_KEY_BASE}-guest`;
    };

    // Cargar carrito al cambiar usuario o al inicializar
    useEffect(() => {
        const cartKey = getCartKey();
        const savedCart = localStorage.getItem(cartKey);
        
        if (savedCart) {
            try {
                const items = JSON.parse(savedCart);
                dispatch({
                    type: CART_ACTIONS.LOAD_CART,
                    payload: { items }
                });
            } catch (error) {
                console.error('Error loading cart:', error);
                localStorage.setItem(cartKey, JSON.stringify([]));
            }
        }
    }, [user?.rut, isAuthenticated]);

    // Funciones del carrito
    const addToCart = (producto, cantidad = 1) => {
        dispatch({
            type: CART_ACTIONS.ADD_ITEM,
            payload: { ...producto, cantidad, cartKey: getCartKey() }
        });
    };

    const removeFromCart = (productId) => {
        dispatch({
            type: CART_ACTIONS.REMOVE_ITEM,
            payload: { productId, cartKey: getCartKey() }
        });
    };

    const updateQuantity = (productId, cantidad) => {
        dispatch({
            type: CART_ACTIONS.UPDATE_QUANTITY,
            payload: { productId, cantidad, cartKey: getCartKey() }
        });
    };

    const clearCart = () => {
        dispatch({
            type: CART_ACTIONS.CLEAR_CART,
            payload: { cartKey: getCartKey() }
        });
    };

    // Funciones de utilidad
    const isInCart = (productId) => {
        return state.items.some(item => item.id === productId);
    };

    const getItemQuantity = (productId) => {
        const item = state.items.find(item => item.id === productId);
        return item ? item.cantidad : 0;
    };

    const getTotalPrice = () => {
        return state.items.reduce((total, item) => total + (item.precio * item.cantidad), 0);
    };

    const getTotalItems = () => {
        return state.items.reduce((total, item) => total + item.cantidad, 0);
    };

    const value = {
        // Estado
        cart: state.items,
        cartVersion: state.version, // Para forzar re-renders
        
        // Funciones
        addToCart,
        removeFromCart,
        updateQuantity,
        clearCart,
        isInCart,
        getItemQuantity,
        getTotalPrice,
        getTotalItems,
        
        // Métricas
        cartCount: state.items.length,
        totalItems: getTotalItems()
    };

    return (
        <CartContext.Provider value={value}>
            {children}
        </CartContext.Provider>
    );
};

